import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface Student {
  id: string;
  name: string;
  class: string;
}

export interface Question {
  number: number;
  correctAnswer: string;
  point: number;
}

export interface StudentAnswer {
  studentId: string;
  answers: Record<number, string>; // Question number to answer
}

export interface ScoringResult {
  student: Student;
  score: number;
  totalPoints: number;
  accuracy: number;
  details: {
    questionNumber: number;
    correctAnswer: string;
    studentAnswer: string;
    isCorrect: boolean;
    point: number;
  }[];
}

import React, { useState, useCallback, useMemo } from 'react';
import { Student, Question, StudentAnswer, ScoringResult } from './types';
import { ScoringTable } from './components/ScoringTable';
import { SetupForm } from './components/SetupForm';
import { ResultReport } from './components/ResultReport';

const App: React.FC = () => {
  const [students, setStudents] = useState<Student[]>([]);
  const [questions, setQuestions] = useState<Question[]>([]);
  const [results, setResults] = useState<ScoringResult[]>([]);
  const [step, setStep] = useState<'setup' | 'results'>('setup');

  const handleProcessAnswers = (answers: StudentAnswer[]) => {
    const newResults: ScoringResult[] = answers.map(ans => {
      const student = students.find(s => s.id === ans.studentId) || { id: ans.studentId, name: '未登録生徒', class: '-' };

      let totalPoints = 0;
      let score = 0;
      const details = questions.map(q => {
        const studentAns = ans.answers[q.number] || "";
        const isCorrect = studentAns === q.correctAnswer;
        totalPoints += q.point;
        if (isCorrect) score += q.point;

        return {
          questionNumber: q.number,
          correctAnswer: q.correctAnswer,
          studentAnswer: studentAns,
          isCorrect,
          point: q.point
        };
      });

      return {
        student,
        score,
        totalPoints,
        accuracy: totalPoints > 0 ? (score / totalPoints) * 100 : 0,
        details
      };
    });

    setResults(newResults);
    setStep('results');
  };

  const handleReset = () => {
    if (window.confirm("全てのデータをリセットしますか？")) {
      setResults([]);
      setStep('setup');
    }
  };

  return (
    <div className="min-h-screen">
      {/* Navigation Header */}
      <header className="bg-blue-600 text-white shadow-md p-4 no-print">
        <div className="max-w-6xl mx-auto flex justify-between items-center">
          <div className="flex items-center space-x-2">
            <i className="fa-solid fa-square-check text-2xl"></i>
            <h1 className="text-xl font-bold font-sans">SmartGrader</h1>
          </div>
          <div className="flex space-x-4">
            {step === 'results' && (
              <>
                <button 
                  onClick={() => window.print()}
                  className="bg-green-500 hover:bg-green-600 px-4 py-2 rounded-lg font-medium transition-colors"
                >
                  <i className="fa-solid fa-print mr-2"></i>一括印刷
                </button>
                <button 
                  onClick={handleReset}
                  className="bg-blue-700 hover:bg-blue-800 px-4 py-2 rounded-lg font-medium transition-colors"
                >
                  <i className="fa-solid fa-rotate-left mr-2"></i>再設定
                </button>
              </>
            )}
          </div>
        </div>
      </header>

      <main className="max-w-6xl mx-auto py-8 px-4">
        {step === 'setup' ? (
          <SetupForm 
            onStudentsChange={setStudents}
            onQuestionsChange={setQuestions}
            onProcessAnswers={handleProcessAnswers}
          />
        ) : (
          <div className="space-y-8">
            <div className="no-print bg-white p-6 rounded-xl shadow-sm border border-slate-200">
              <h2 className="text-lg font-bold text-slate-800 mb-2">採点完了</h2>
              <p className="text-slate-600 mb-4">{results.length} 名の生徒の採点が完了しました。各生徒の成績個票は、以下の「印刷」ボタンまたはブラウザの印刷機能（Ctrl+P / Cmd+P）を使用してA4用紙に印刷できます。</p>
              <div className="flex flex-wrap gap-4">
                <div className="bg-blue-50 border border-blue-100 p-4 rounded-lg flex-1 min-w-[200px]">
                  <span className="text-sm text-blue-600 font-bold block mb-1">平均正答率</span>
                  <span className="text-3xl font-bold text-blue-800">
                    {(results.reduce((acc, r) => acc + r.accuracy, 0) / results.length).toFixed(1)}%
                  </span>
                </div>
                <div className="bg-green-50 border border-green-100 p-4 rounded-lg flex-1 min-w-[200px]">
                  <span className="text-sm text-green-600 font-bold block mb-1">最高点</span>
                  <span className="text-3xl font-bold text-green-800">
                    {Math.max(...results.map(r => r.score))}点
                  </span>
                </div>
              </div>
            </div>

            <div className="space-y-12">
              {results.map((result, idx) => (
                <ResultReport key={result.student.id} result={result} />
              ))}
            </div>
          </div>
        )}
      </main>

      <footer className="mt-20 py-8 text-center text-slate-400 text-sm border-t border-slate-200 no-print">
        <p>&copy; 2024 SmartGrader - Education Solution Tools</p>
      </footer>
    </div>
  );
};

export default App;

import React, { useState } from 'react';
import { Student, Question, StudentAnswer } from '../types';

interface SetupFormProps {
  onStudentsChange: (students: Student[]) => void;
  onQuestionsChange: (questions: Question[]) => void;
  onProcessAnswers: (answers: StudentAnswer[]) => void;
}

export const SetupForm: React.FC<SetupFormProps> = ({
  onStudentsChange,
  onQuestionsChange,
  onProcessAnswers
}) => {
  const [studentText, setStudentText] = useState('');
  const [questionText, setQuestionText] = useState('');
  const [csvContent, setCsvContent] = useState<string | null>(null);

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = (event) => {
      setCsvContent(event.target?.result as string);
    };
    reader.readAsText(file);
  };

  const processAll = () => {
    // 1. Parse Students (ID,Name,Class)
    const studentLines = studentText.trim().split('\n');
    const parsedStudents: Student[] = studentLines.filter(l => l.includes(',')).map(line => {
      const [id, name, cls] = line.split(',').map(s => s.trim());
      return { id, name, class: cls || '-' };
    });

    // 2. Parse Questions (No,Answer,Point)
    const questionLines = questionText.trim().split('\n');
    const parsedQuestions: Question[] = questionLines.filter(l => l.includes(',')).map(line => {
      const [no, ans, p] = line.split(',').map(s => s.trim());
      return { number: parseInt(no), correctAnswer: ans, point: parseFloat(p) };
    });

    if (parsedStudents.length === 0 || parsedQuestions.length === 0 || !csvContent) {
      alert("生徒情報、問題設定、解答CSVのすべてを正しく入力・アップロードしてください。");
      return;
    }

    // 3. Parse CSV Answers (StudentID, Q1, Q2, ...)
    const csvLines = csvContent.trim().split('\n');
    // Header can be skipped if you assume fixed format or use it to map
    const studentAnswers: StudentAnswer[] = csvLines.slice(1).map(line => {
      const parts = line.split(',').map(s => s.trim());
      const studentId = parts[0];
      const answers: Record<number, string> = {};

      // We map the remaining columns to the question numbers defined
      parsedQuestions.forEach((q, idx) => {
        // Assuming column 1 is Q1, column 2 is Q2, etc.
        answers[q.number] = parts[idx + 1] || "";
      });

      return { studentId, answers };
    });

    onStudentsChange(parsedStudents);
    onQuestionsChange(parsedQuestions);
    onProcessAnswers(studentAnswers);
  };

  return (
    <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
      {/* Student Config */}
      <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-200">
        <div className="flex items-center space-x-2 mb-4">
          <div className="w-8 h-8 bg-blue-100 text-blue-600 rounded-full flex items-center justify-center font-bold">1</div>
          <h3 className="font-bold text-slate-800">生徒情報の登録</h3>
        </div>
        <p className="text-sm text-slate-500 mb-2">CSV形式（生徒番号,名前,クラス）で1行ずつ入力</p>
        <textarea
          className="w-full h-40 p-3 border border-slate-300 rounded-lg font-mono text-sm focus:ring-2 focus:ring-blue-500 focus:border-transparent outline-none"
          placeholder="S001,山田 太郎,3-A&#10;S002,佐藤 花子,3-A"
          value={studentText}
          onChange={(e) => setStudentText(e.target.value)}
        />
      </div>

      {/* Questions Config */}
      <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-200">
        <div className="flex items-center space-x-2 mb-4">
          <div className="w-8 h-8 bg-blue-100 text-blue-600 rounded-full flex items-center justify-center font-bold">2</div>
          <h3 className="font-bold text-slate-800">正解・配点の設定</h3>
        </div>
        <p className="text-sm text-slate-500 mb-2">CSV形式（問題番号,正解,配点）で1行ずつ入力</p>
        <textarea
          className="w-full h-40 p-3 border border-slate-300 rounded-lg font-mono text-sm focus:ring-2 focus:ring-blue-500 focus:border-transparent outline-none"
          placeholder="1,A,5&#10;2,B,5&#10;3,C,10"
          value={questionText}
          onChange={(e) => setQuestionText(e.target.value)}
        />
      </div>

      {/* CSV Upload */}
      <div className="lg:col-span-2 bg-white p-6 rounded-xl shadow-sm border border-slate-200">
        <div className="flex items-center space-x-2 mb-4">
          <div className="w-8 h-8 bg-blue-100 text-blue-600 rounded-full flex items-center justify-center font-bold">3</div>
          <h3 className="font-bold text-slate-800">マークシート解答データの読み込み</h3>
        </div>
        <div className="flex items-center space-x-4">
          <div className="flex-1">
            <label className="block text-sm font-medium text-slate-700 mb-1">
              マークシート読取済みCSVファイルを選択
            </label>
            <input
              type="file"
              accept=".csv"
              onChange={handleFileUpload}
              className="block w-full text-sm text-slate-500 file:mr-4 file:py-2 file:px-4 file:rounded-full file:border-0 file:text-sm file:font-semibold file:bg-blue-50 file:text-blue-700 hover:file:bg-blue-100"
            />
          </div>
          <div className="flex flex-col text-xs text-slate-400 italic">
            <span>※ A列: 生徒番号</span>
            <span>※ B列以降: 各問題の解答</span>
          </div>
        </div>

        <div className="mt-8 pt-6 border-t border-slate-100 text-center">
          <button
            onClick={processAll}
            className="bg-blue-600 hover:bg-blue-700 text-white font-bold py-3 px-12 rounded-full shadow-lg transition-transform active:scale-95 text-lg"
          >
            <i className="fa-solid fa-calculator mr-2"></i>採点を実行する
          </button>
        </div>
      </div>
    </div>
  );
};

