import React, { useState } from 'react';
import { Student, Question, StudentAnswer } from '../types';

interface SetupFormProps {
  onStudentsChange: (students: Student[]) => void;
  onQuestionsChange: (questions: Question[]) => void;
  onProcessAnswers: (answers: StudentAnswer[]) => void;
}

export const SetupForm: React.FC<SetupFormProps> = ({
  onStudentsChange,
  onQuestionsChange,
  onProcessAnswers
}) => {
  const [studentText, setStudentText] = useState('');
  const [questionText, setQuestionText] = useState('');
  const [csvContent, setCsvContent] = useState<string | null>(null);

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    const reader = new FileReader();
    reader.onload = (event) => setCsvContent(event.target?.result as string);
    reader.readAsText(file);
  };

  const processAll = () => {
    const studentLines = studentText.trim().split('\n');
    const parsedStudents: Student[] = studentLines.filter(l => l.includes(',')).map(line => {
      const [id, name, cls] = line.split(',').map(s => s.trim());
      return { id, name, class: cls || '-' };
    });

    const questionLines = questionText.trim().split('\n');
    const parsedQuestions: Question[] = questionLines.filter(l => l.includes(',')).map(line => {
      const [no, ans, p] = line.split(',').map(s => s.trim());
      return { number: parseInt(no), correctAnswer: ans, point: parseFloat(p) };
    });

    if (parsedStudents.length === 0 || parsedQuestions.length === 0 || !csvContent) {
      alert("設定を完了させてください（生徒、正解、CSVデータ）");
      return;
    }

    const csvLines = csvContent.trim().split('\n');
    const studentAnswers: StudentAnswer[] = csvLines.slice(1).map(line => {
      const parts = line.split(',').map(s => s.trim());
      const studentId = parts[0];
      const answers: Record<number, string> = {};
      parsedQuestions.forEach((q, idx) => {
        answers[q.number] = parts[idx + 1] || "";
      });
      return { studentId, answers };
    });

    onStudentsChange(parsedStudents);
    onQuestionsChange(parsedQuestions);
    onProcessAnswers(studentAnswers);
  };

  return (
    <div className="grid grid-cols-2 gap-8 h-full">
      <div className="space-y-8">
        <div className="bg-black/40 p-6 rounded border border-white/10">
          <h3 className="f1-font font-black italic text-lg mb-4 flex items-center">
            <span className="bg-[#e10600] w-2 h-6 mr-3"></span>生徒名簿登録
          </h3>
          <textarea
            className="w-full h-40 bg-black/60 border border-white/20 rounded p-4 text-sm font-mono focus:border-[#e10600] outline-none"
            placeholder="生徒番号,氏名,クラス&#10;S001,山田 太郎,3-A"
            value={studentText}
            onChange={(e) => setStudentText(e.target.value)}
          />
        </div>

        <div className="bg-black/40 p-6 rounded border border-white/10">
          <h3 className="f1-font font-black italic text-lg mb-4 flex items-center">
            <span className="bg-[#e10600] w-2 h-6 mr-3"></span>正解・配点設定
          </h3>
          <textarea
            className="w-full h-40 bg-black/60 border border-white/20 rounded p-4 text-sm font-mono focus:border-[#e10600] outline-none"
            placeholder="問題番号,正解,配点&#10;1,A,5"
            value={questionText}
            onChange={(e) => setQuestionText(e.target.value)}
          />
        </div>
      </div>

      <div className="space-y-8">
        <div className="bg-black/40 p-6 rounded border border-white/10 h-full flex flex-col">
          <h3 className="f1-font font-black italic text-lg mb-4 flex items-center">
            <span className="bg-[#e10600] w-2 h-6 mr-3"></span>解答CSVアップロード
          </h3>
          <div className="flex-1 border-2 border-dashed border-white/10 rounded flex flex-col items-center justify-center p-8 text-center relative hover:bg-white/5 transition-all">
             <input type="file" accept=".csv" onChange={handleFileUpload} className="absolute inset-0 opacity-0 cursor-pointer" />
             <i className="fa-solid fa-cloud-arrow-up text-5xl text-white/10 mb-4"></i>
             <p className="f1-font font-bold text-white/40 italic">
               {csvContent ? "FILE READY" : "UPLOAD TELEMETRY CSV"}
             </p>
          </div>
        </div>
      </div>

      <button id="process-trigger" onClick={processAll} className="hidden" />
    </div>
  );
};

