import React, { useState } from 'react';
import { Student, Question, StudentAnswer, ScoringResult } from './types';
import { SetupForm } from './components/SetupForm';
import { ResultReport } from './components/ResultReport';

const App: React.FC = () => {
  const [students, setStudents] = useState<Student[]>([]);
  const [questions, setQuestions] = useState<Question[]>([]);
  const [results, setResults] = useState<ScoringResult[]>([]);
  const [lap, setLap] = useState<1 | 2 | 3 | 4>(1);

  const handleProcessAnswers = (answers: StudentAnswer[]) => {
    const newResults: ScoringResult[] = answers.map(ans => {
      const student = students.find(s => s.id === ans.studentId) || { id: ans.studentId, name: '未登録', class: '-' };
      let totalPoints = 0;
      let score = 0;
      const details = questions.map(q => {
        const studentAns = ans.answers[q.number] || "";
        const isCorrect = studentAns === q.correctAnswer;
        totalPoints += q.point;
        if (isCorrect) score += q.point;
        return { questionNumber: q.number, correctAnswer: q.correctAnswer, studentAnswer: studentAns, isCorrect, point: q.point };
      });
      return { student, score, totalPoints, accuracy: totalPoints > 0 ? (score / totalPoints) * 100 : 0, details };
    });
    setResults(newResults.sort((a, b) => b.score - a.score));
    setLap(4);
  };

  const resetAll = () => {
    setStudents([]);
    setQuestions([]);
    setResults([]);
    setLap(1);
  };

  return (
    <div className="min-h-screen flex flex-col overflow-hidden">
      <header className="no-print h-24 flex items-center px-12 bg-[#15151e]">
        <div className="border-4 border-white p-2 pr-12 rounded-tr-3xl rounded-bl-3xl flex items-center cursor-pointer" onClick={resetAll}>
