        </div>
        <div className="ml-12 flex items-center space-x-2">
           {[1, 2, 3, 4].map(l => (
             <div key={l} className={`h-2 w-16 skew-x-[-20deg] ${lap >= l ? 'bg-[#e10600]' : 'bg-white/10'}`}></div>
           ))}
           <span className="f1-font font-black italic ml-4 text-xl">LAP {lap}/4</span>
        </div>
        <div className="ml-auto">
          {lap === 4 && (
            <button onClick={() => window.print()} className="f1-font bg-white text-black px-8 py-2 rounded font-black italic mr-4">PRINT ALL</button>
          )}
          {lap === 4 && (
            <button onClick={resetAll} className="f1-font bg-[#e10600] text-white px-8 py-2 rounded font-black italic">NEW SESSION</button>
          )}
        </div>
      </header>

      <main className="flex-1 p-8 overflow-hidden flex flex-col">
        {lap < 4 ? (
          <div className="flex-1 flex flex-col">
             <SetupForm 
                lap={lap} 
                setLap={setLap} 
                students={students} 
                setStudents={setStudents}
                questions={questions}
                setQuestions={setQuestions}
                onProcess={handleProcessAnswers}
             />
          </div>
        ) : (
          <div className="flex-1 overflow-y-auto pr-4 space-y-20">
             <div className="no-print dashboard-card p-6 flex items-center justify-between border-b-4 border-[#00ffd2] mb-12">
                <div className="f1-font">
                   <h2 className="text-3xl font-black italic uppercase">Final Classification</h2>
                   <p className="text-[#00ffd2] text-xs font-bold tracking-widest uppercase">Telemetry verified // {results.length} Drivers Finish</p>
                </div>
                <div className="flex space-x-8">
                  <div className="text-center">
                    <p className="text-[10px] font-bold text-white/40 uppercase">Average Efficiency</p>
                    <p className="f1-font text-4xl font-black italic text-[#00ffd2]">
                      {(results.reduce((acc, r) => acc + r.accuracy, 0) / results.length).toFixed(1)}%
                    </p>
                  </div>
                </div>
             </div>
             {results.map(r => <ResultReport key={r.student.id} result={r} />)}
          </div>
        )}
      </main>

      <footer className="h-14 bg-[#15151e] border-t border-white/10 flex items-center px-8 no-print">
        <div className="bg-white p-1 px-4 text-black font-black italic mr-4 f1-font">FIA</div>
        <div className="flex-1 text-sm font-bold tracking-tight overflow-hidden whitespace-nowrap">
