export default App;

import React, { useState, useEffect } from 'react';
import { Student, Question, StudentAnswer } from '../types';

interface SetupFormProps {
  lap: 1 | 2 | 3 | 4;
  setLap: (lap: any) => void;
  students: Student[];
  setStudents: (s: Student[]) => void;
  questions: Question[];
  setQuestions: (q: Question[] | ((prev: Question[]) => Question[])) => void;
  onProcess: (answers: StudentAnswer[]) => void;
}

export const SetupForm: React.FC<SetupFormProps> = ({
  lap, setLap, students, setStudents, questions, setQuestions, onProcess
}) => {
  const [qCount, setQCount] = useState(10);
  const [selectedPoint, setSelectedPoint] = useState(5);
  const [isDragging, setIsDragging] = useState(false);

  const handleStudentUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    const reader = new FileReader();
    reader.onload = (event) => {
      const csvLines = (event.target?.result as string).trim().split('\n');
      const parsed = csvLines.slice(1).map(line => {
        const [grade, cls, num, name] = line.split(',').map(s => s.trim());
        if (!grade || !cls || !num) return null;
        const paddedNum = num.padStart(2, '0');
        const id = `${grade}${cls}${paddedNum}`;
        return { 
          id, 
          name: name || `生徒 ${paddedNum}`, 
          class: `${grade}年${cls}組` 
        };
      }).filter((s): s is Student => s !== null);
      setStudents(parsed);
    };
    reader.readAsText(file);
  };

  const downloadStudentTemplate = () => {
    const bom = new Uint8Array([0xEF, 0xBB, 0xBF]);
    const csvContent = "grade,class,number,name\n1,A,01,山田 太郎\n1,A,02,佐藤 花子";
    const blob = new Blob([bom, csvContent], { type: 'text/csv;charset=utf-8' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url; a.download = 'driver_entry_template.csv'; a.click();
  };

  useEffect(() => {
    if (lap === 2 && questions.length === 0) {
      const initQ = Array.from({ length: qCount }, (_, i) => ({
        number: i + 1, correctAnswer: '', point: 5
      }));
      setQuestions(initQ);
    }
  }, [lap, qCount, questions.length, setQuestions]);

  const updateQ = (no: number, field: keyof Question, val: any) => {
    setQuestions((prev: Question[]) => prev.map(q => q.number === no ? { ...q, [field]: val } : q));
  };

  const handleCellEnter = (no: number) => {
    if (isDragging) {
      updateQ(no, 'point', selectedPoint);
    }
  };

  const handlePointChange = (val: string) => {
    const num = parseInt(val);
    if (!isNaN(num)) {
      setSelectedPoint(Math.min(Math.max(num, 1), 100));
    }
  };

  const downloadAnswersTemplate = () => {
    const bom = new Uint8Array([0xEF, 0xBB, 0xBF]);
    const headers = ["student_id", ...questions.map(q => `Q${q.number}`)].join(',');
    const rows = students.map(s => `${s.id},${questions.map(() => "").join(',')}`).join('\n');
    const csvContent = `${headers}\n${rows}`;
    const blob = new Blob([bom, csvContent], { type: 'text/csv;charset=utf-8' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url; a.download = 'telemetry_upload_sheet.csv'; a.click();
  };

  const handleFinalUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    const reader = new FileReader();
    reader.onload = (event) => {
      const lines = (event.target?.result as string).trim().split('\n');
      const answers: StudentAnswer[] = lines.slice(1).map(line => {
        const parts = line.split(',').map(s => s.trim());
        const ans: Record<number, string> = {};
        questions.forEach((q, idx) => {
          ans[q.number] = parts[idx + 1] || "";
        });
        return { studentId: parts[0], answers: ans };
      });
      onProcess(answers);
    };
    reader.readAsText(file);
  };

  return (
    <div className="flex-1 flex flex-col space-y-8" onMouseUp={() => setIsDragging(false)}>
      {lap === 1 && (
        <div className="max-w-4xl mx-auto w-full space-y-8">
           <div className="bg-[#1f1f27] p-8 rounded border-b-4 border-[#e10600]">
              <h2 className="f1-font text-3xl font-black italic mb-2 uppercase">Lap 1: Driver Entry</h2>
              <p className="text-white/40 mb-8 uppercase text-xs font-bold tracking-widest">ドライバー名簿（学年,クラス,番号,氏名）をCSVで登録してください</p>

              <div className="grid grid-cols-2 gap-8">
                <button onClick={downloadStudentTemplate} className="h-40 border-2 border-dashed border-white/10 rounded flex flex-col items-center justify-center hover:bg-white/5 transition-all group">
                   <i className="fa-solid fa-file-csv text-5xl text-white/20 group-hover:text-white transition-all mb-4"></i>
                   <span className="f1-font text-sm italic font-bold">1. TEMPLATE DOWNLOAD</span>
                </button>
                <div className="h-40 border-2 border-dashed border-white/10 rounded flex flex-col items-center justify-center relative hover:bg-white/5 transition-all">
                   <input type="file" accept=".csv" onChange={handleStudentUpload} className="absolute inset-0 opacity-0 cursor-pointer" />
                   <i className="fa-solid fa-cloud-arrow-up text-5xl text-[#e10600] mb-4"></i>
                   <span className="f1-font text-sm italic font-bold">2. UPLOAD CSV</span>
                </div>
              </div>

              {students.length > 0 && (
                <div className="mt-8 flex items-center justify-between bg-[#00ffd2]/10 p-4 rounded border border-[#00ffd2]/30">
                   <div className="flex flex-col">
                      <span className="f1-font font-black italic text-[#00ffd2] uppercase leading-none">{students.length} 名を登録済み</span>
                   </div>
                   <button onClick={() => setLap(2)} className="f1-font bg-[#00ffd2] text-black px-12 py-3 font-black italic rounded skew-x-[-10deg] shadow-[0_0_15px_rgba(0,255,210,0.3)] hover:scale-105 transition-transform">
                      TECH SETUP へ進む <i className="fa-solid fa-chevron-right ml-2"></i>
                   </button>
                </div>
              )}
           </div>
        </div>
      )}

      {lap === 2 && (
        <div className="flex-1 flex flex-col overflow-hidden">
           <div className="bg-[#1f1f27] p-6 rounded-t border-b border-white/10 flex items-center justify-between no-print">
              <div className="flex items-center space-x-4">
                 <button onClick={() => setLap(1)} className="w-10 h-10 rounded-full border border-white/20 flex items-center justify-center hover:bg-white/5 transition-colors text-white/60 hover:text-white">
                    <i className="fa-solid fa-arrow-left"></i>
                 </button>
                 <div>
                    <h2 className="f1-font text-2xl font-black italic uppercase">Lap 2: Technical Setup</h2>
                    <p className="text-white/40 uppercase text-[10px] font-bold tracking-widest">問題数・正解・配点を設定してください</p>
                 </div>
              </div>
              <div className="flex items-center space-x-6">
                <div className="flex items-center space-x-2">
                  <span className="text-[10px] font-bold text-white/40 uppercase">問題数:</span>
                  <input 
                    type="number" min="1" value={qCount} onChange={(e) => {
                      const val = parseInt(e.target.value);
                      if (isNaN(val) || val < 1) return;
                      setQCount(val);
                      setQuestions(Array.from({ length: val }, (_, i) => ({ number: i + 1, correctAnswer: '', point: selectedPoint })));
                    }}
                    className="bg-black/60 border border-white/20 text-white w-16 p-1 f1-font text-center font-bold outline-none"
                  />
                </div>
                <div className="h-8 w-px bg-white/10"></div>
                <div className="flex items-center space-x-2">
                  <span className="text-[10px] font-bold text-white/40 uppercase">配点:</span>
                  <input 
                    type="number" min="1" value={selectedPoint}
                    onChange={(e) => handlePointChange(e.target.value)}
                    className="bg-[#e10600] border-none text-white w-12 p-1 f1-font text-center font-bold outline-none"
                  />
                  <div className="flex space-x-1 ml-2">
                    {[1, 2, 3, 5, 10].map(p => (
                      <button 
                        key={p} onClick={() => setSelectedPoint(p)}
                        className={`w-8 h-8 rounded-sm f1-font text-[10px] font-bold border transition-all ${selectedPoint === p ? 'bg-white text-black border-white' : 'border-white/20 text-white/40 hover:text-white'}`}
                      >
                        {p}
                      </button>
                    ))}
                  </div>
                </div>
                <button onClick={() => setLap(3)} className="f1-font bg-[#e10600] text-white px-8 py-2 font-black italic rounded skew-x-[-10deg]">NEXT LAP</button>
              </div>
           </div>

           <div className="flex-1 overflow-y-auto bg-black/20 p-6 no-print">
              <div className="grid grid-cols-2 md:grid-cols-5 lg:grid-cols-10 gap-2">
                 {questions.map(q => (
                   <div key={q.number} className="bg-[#1f1f27] border border-white/10 rounded overflow-hidden">
                      <div className="bg-white/5 p-1 text-center text-[10px] f1-font font-black italic text-white/40 border-b border-white/5 uppercase">Q{q.number}</div>
                      <div className="p-2 space-y-2">
                         <input 
                           type="text" maxLength={1} value={q.correctAnswer} 
                           onChange={(e) => updateQ(q.number, 'correctAnswer', e.target.value.toUpperCase())}
                           className="w-full bg-black border border-white/10 rounded p-1 text-center font-black f1-font text-[#00ffd2] outline-none"
                         />
                         <div 
                           onMouseDown={() => { setIsDragging(true); updateQ(q.number, 'point', selectedPoint); }}
                           onMouseEnter={() => handleCellEnter(q.number)}
                           className="cursor-pointer bg-white/5 rounded py-1 text-center text-xs font-black f1-font text-white border border-white/5 select-none"
                         >
                           {q.point}
                         </div>
                      </div>
                   </div>
                 ))}
              </div>
           </div>
        </div>
      )}

      {lap === 3 && (
        <div className="max-w-4xl mx-auto w-full space-y-8">
           <div className="bg-[#1f1f27] p-8 rounded border-b-4 border-[#e10600]">
              <div className="flex items-center justify-between mb-8">
                <div className="flex items-center space-x-4">
                  <button onClick={() => setLap(2)} className="w-10 h-10 rounded-full border border-white/20 flex items-center justify-center hover:bg-white/5 transition-colors text-white/60 hover:text-white">
                    <i className="fa-solid fa-arrow-left"></i>
                  </button>
                  <h2 className="f1-font text-3xl font-black italic uppercase">Lap 3: Data Analysis</h2>
                </div>
              </div>
              <div className="grid grid-cols-2 gap-8">
                <button onClick={downloadAnswersTemplate} className="h-40 border-2 border-dashed border-white/10 rounded flex flex-col items-center justify-center hover:bg-white/5 transition-all group">
                   <i className="fa-solid fa-file-export text-4xl text-[#00ffd2] mb-2"></i>
                   <span className="f1-font text-sm italic font-bold">1. 解答用シートDL</span>
                </button>
                <div className="h-40 border-2 border-dashed border-white/10 rounded flex flex-col items-center justify-center relative hover:bg-white/5 transition-all">
                   <input type="file" accept=".csv" onChange={handleFinalUpload} className="absolute inset-0 opacity-0 cursor-pointer" />
                   <i className="fa-solid fa-microchip text-4xl text-[#e10600] mb-2"></i>
                   <span className="f1-font text-sm italic font-bold">2. 完了済みデータUP</span>
                </div>
              </div>
           </div>
        </div>
      )}
    </div>
  );
};

