                </tr>
              ))}
            </tbody>
          </table>
        </div>

        {/* 視覚的フィードバック */}
        <div className="bg-slate-50 p-6 border border-slate-200">
          <div className="flex justify-between items-center mb-4">
             <span className="text-[11px] font-black tracking-widest text-slate-500">解答状況ビジュアライザー</span>
             <span className="text-[10px] font-black text-slate-400">ANALYSIS COMPLETE</span>
          </div>
          <div className="flex h-3 gap-1">
            {result.details.map((d, i) => (
              <div key={i} className={`flex-1 ${d.isCorrect ? 'bg-green-400' : 'bg-[#e10600]'}`} />
            ))}
          </div>
        </div>

        {/* フッター */}
        <div className="flex justify-between items-end pt-8 border-t border-slate-200">
           <div className="text-[9px] text-slate-300 italic font-bold">
             GRADED BY SMARTGRADER // SYSTEM VERIFIED
           </div>
           <div className="bg-slate-800 text-white px-6 py-1 f1-font font-black italic text-xs skew-x-[-10deg]">
             OFFICIAL RESULT
           </div>
        </div>
      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { Student, Question, StudentAnswer, ScoringResult, ArchiveData } from './types';
import { SetupForm } from './components/SetupForm';
import { ResultReport } from './components/ResultReport';

const App: React.FC = () => {
  const [students, setStudents] = useState<Student[]>([]);
  const [questions, setQuestions] = useState<Question[]>([]);
  const [results, setResults] = useState<ScoringResult[]>([]);
  const [lap, setLap] = useState<1 | 2 | 3 | 4>(1);
  const [isAnimating, setIsAnimating] = useState(false);
  const [archives, setArchives] = useState<ArchiveData[]>([]);
  const [selectedResultIndex, setSelectedResultIndex] = useState<number>(0);

  useEffect(() => {
    const saved = localStorage.getItem('grader_archives');
    if (saved) setArchives(JSON.parse(saved));
  }, []);

  const triggerLapChange = (nextLap: 1 | 2 | 3 | 4) => {
    setIsAnimating(true);
    setTimeout(() => {
      setLap(nextLap);
      setTimeout(() => setIsAnimating(false), 500);
    }, 400);
  };

  const saveToArchive = (newResults: ScoringResult[]) => {
    const archive: ArchiveData = {
      id: Date.now().toString(),
      timestamp: new Date().toLocaleString(),
      name: `${new Date().toLocaleDateString()} 採点セッション`,
      results: newResults,
      questions,
      students
    };
    const updated = [archive, ...archives];
    setArchives(updated);
    localStorage.setItem('grader_archives', JSON.stringify(updated));
  };

  const deleteArchive = (id: string) => {
    const updated = archives.filter(a => a.id !== id);
    setArchives(updated);
    localStorage.setItem('grader_archives', JSON.stringify(updated));
  };

  const loadArchive = (archive: ArchiveData) => {
    setStudents(archive.students);
    setQuestions(archive.questions);
    setResults(archive.results);
    setSelectedResultIndex(0);
    triggerLapChange(4);
  };

  const handleProcessAnswers = (answers: StudentAnswer[]) => {
    const newResults: ScoringResult[] = answers.map(ans => {
      const student = students.find(s => s.id === ans.studentId) || { id: ans.studentId, name: '未登録', class: '-' };
      let totalPoints = 0;
      let score = 0;
      const details = questions.map(q => {
        const studentAns = ans.answers[q.number] || "";
        const isCorrect = studentAns === q.correctAnswer;
        totalPoints += q.point;
        if (isCorrect) score += q.point;
        return { questionNumber: q.number, correctAnswer: q.correctAnswer, studentAnswer: studentAns, isCorrect, point: q.point };
      });
      return { student, score, totalPoints, accuracy: totalPoints > 0 ? (score / totalPoints) * 100 : 0, details };
    });

    // 学年、クラス、番号順にソート (IDが grade+class+number なので文字列順でOK)
    const sorted = newResults.sort((a, b) => a.student.id.localeCompare(b.student.id));

    setResults(sorted);
    saveToArchive(sorted);
    triggerLapChange(4);
  };

  const resetAll = () => {
    setStudents([]);
    setQuestions([]);
    setResults([]);
    triggerLapChange(1);
  };

  const nextDriver = () => {
    setSelectedResultIndex((prev) => (prev + 1) % results.length);
  };

  const prevDriver = () => {
    setSelectedResultIndex((prev) => (prev - 1 + results.length) % results.length);
  };

  return (
    <div className={`min-h-screen flex flex-col overflow-hidden relative ${isAnimating ? 'animate-pulse-fast' : ''}`}>
      {isAnimating && (
        <div className="fixed inset-0 z-[100] pointer-events-none overflow-hidden flex items-center justify-center">
          <div className="absolute inset-0 bg-black/40 backdrop-blur-sm transition-opacity duration-300"></div>
          <div className="relative w-full h-32 bg-[#e10600] skew-y-[-5deg] flex items-center justify-center animate-slide-across shadow-[0_0_100px_rgba(225,6,0,0.5)]">
             <div className="f1-font text-white text-6xl font-black italic tracking-tighter uppercase animate-bounce">BOX BOX BOX</div>
          </div>
          <div className="absolute right-full w-[200vw] h-1 bg-white/50 animate-race-line"></div>
        </div>
      )}

      <header className="no-print h-24 flex items-center px-12 bg-[#15151e] shrink-0">
        <div className="border-4 border-white p-2 pr-12 rounded-tr-3xl rounded-bl-3xl flex items-center cursor-pointer" onClick={resetAll}>
          <span className="f1-font text-4xl font-black italic tracking-tighter text-white uppercase">Grader Graphics</span>
        </div>
        <div className="ml-12 flex items-center space-x-2">
           {[1, 2, 3, 4].map(l => (
             <div key={l} className={`h-2 w-16 skew-x-[-20deg] transition-all duration-500 ${lap >= l ? 'bg-[#e10600] shadow-[0_0_10px_#e10600]' : 'bg-white/10'}`}></div>
           ))}
           <span className="f1-font font-black italic ml-4 text-xl">LAP {lap}/4</span>
        </div>
        <div className="ml-auto">
          {lap === 4 && (
            <div className="flex items-center space-x-4">
              <div className="flex items-center bg-black border border-[#00ffd2] rounded overflow-hidden">
                <button onClick={prevDriver} className="px-4 py-2 hover:bg-[#00ffd2]/20 text-[#00ffd2] transition-colors">
                  <i className="fa-solid fa-chevron-left"></i>
                </button>
                <select 
                  value={selectedResultIndex} 
                  onChange={(e) => setSelectedResultIndex(parseInt(e.target.value))}
                  className="bg-transparent text-white p-2 f1-font text-sm outline-none border-x border-[#00ffd2]/30 min-w-[200px]"
                >
                  {results.map((r, i) => (
                    <option key={r.student.id} value={i}>
                      {r.student.class} {r.student.id.slice(-2)}番: {r.student.name}
                    </option>
                  ))}
                </select>
                <button onClick={nextDriver} className="px-4 py-2 hover:bg-[#00ffd2]/20 text-[#00ffd2] transition-colors">
                  <i className="fa-solid fa-chevron-right"></i>
                </button>
              </div>
              <button onClick={() => window.print()} className="f1-font bg-white text-black px-6 py-2 rounded font-black italic hover:bg-slate-200">
                <i className="fa-solid fa-file-pdf mr-2"></i>PDF/印刷
              </button>
              <button onClick={resetAll} className="f1-font bg-[#e10600] text-white px-6 py-2 rounded font-black italic">終了</button>
            </div>
          )}
        </div>
      </header>

      <main className="flex-1 p-8 overflow-hidden flex flex-col relative">
        {lap === 4 && results.length > 0 && (
          <div className="no-print absolute top-1/2 left-4 -translate-y-1/2 z-10">
             <button onClick={prevDriver} className="w-12 h-24 bg-black/50 hover:bg-[#e10600] text-white rounded-r-xl transition-all flex items-center justify-center border border-white/10 border-l-0">
               <i className="fa-solid fa-chevron-left text-2xl"></i>
             </button>
          </div>
        )}
        {lap === 4 && results.length > 0 && (
          <div className="no-print absolute top-1/2 right-4 -translate-y-1/2 z-10">
             <button onClick={nextDriver} className="w-12 h-24 bg-black/50 hover:bg-[#e10600] text-white rounded-l-xl transition-all flex items-center justify-center border border-white/10 border-r-0">
               <i className="fa-solid fa-chevron-right text-2xl"></i>
             </button>
          </div>
        )}

        {lap === 1 && (
          <div className="flex flex-col h-full space-y-6">
            <SetupForm lap={1} setLap={triggerLapChange} students={students} setStudents={setStudents} questions={questions} setQuestions={setQuestions} onProcess={handleProcessAnswers} />
            {archives.length > 0 && (
              <div className="bg-[#1f1f27] p-6 rounded border border-white/10">
                <h3 className="f1-font text-xl font-black italic text-white/40 mb-4 uppercase">Archive Records</h3>
                <div className="space-y-2 max-h-48 overflow-y-auto pr-2">
                  {archives.map(a => (
                    <div key={a.id} className="bg-black/40 p-3 rounded flex items-center justify-between border border-white/5 hover:border-[#e10600]/50 transition-colors">
                      <div>
                        <p className="font-bold text-sm">{a.name}</p>
                        <p className="text-[10px] text-white/40">{a.timestamp} - {a.results.length} 名分</p>
                      </div>
                      <div className="flex space-x-2">
                        <button onClick={() => loadArchive(a)} className="text-[10px] font-bold bg-[#00ffd2]/10 text-[#00ffd2] px-3 py-1 rounded hover:bg-[#00ffd2]/20">読み込み</button>
                        <button onClick={() => deleteArchive(a.id)} className="text-[10px] font-bold bg-[#e10600]/10 text-[#e10600] px-3 py-1 rounded hover:bg-[#e10600]/20">削除</button>
                      </div>
                    </div>
                  ))}
                </div>
              </div>
            )}
          </div>
        )}
        {lap > 1 && lap < 4 && (
           <SetupForm lap={lap} setLap={triggerLapChange} students={students} setStudents={setStudents} questions={questions} setQuestions={setQuestions} onProcess={handleProcessAnswers} />
        )}
        {lap === 4 && results[selectedResultIndex] && (
          <div className="flex-1 overflow-y-auto px-12">
            <ResultReport result={results[selectedResultIndex]} />
          </div>
        )}
      </main>

      <footer className="h-14 bg-[#15151e] border-t border-white/10 flex items-center px-8 no-print shrink-0">
        <div className="bg-white p-1 px-4 text-black font-black italic mr-4 f1-font">FIA</div>
        <div className="flex-1 text-sm font-bold tracking-tight overflow-hidden whitespace-nowrap">
           <span className="inline-block animate-[marquee_20s_linear_infinite] uppercase text-white/60">
             {lap === 1 && "ドライバー登録: CSVをアップロードするか過去のアーカイブを選択してください"}
             {lap === 2 && "テクニカル設定: 問題数と正答、配点を設定してください（ドラッグ入力対応）"}
             {lap === 3 && "データ解析: 解答済みテレメトリCSVをアップロードして分析を開始します"}
             {lap === 4 && "ポストレースレポート: 個票を確認し、印刷またはPDF保存が可能です"}
           </span>
        </div>
      </footer>
      <style>{`
        @keyframes marquee { 0% { transform: translateX(100%); } 100% { transform: translateX(-100%); } }
        @keyframes slide-across {
          0% { transform: translateX(-150%) skewY(-5deg); }
          50% { transform: translateX(0) skewY(-5deg); }
          100% { transform: translateX(150%) skewY(-5deg); }
        }
        @keyframes race-line {
          0% { left: -100%; width: 0%; opacity: 1; }
          100% { left: 100%; width: 200%; opacity: 0; }
        }
        .animate-slide-across { animation: slide-across 0.8s cubic-bezier(0.7, 0, 0.3, 1) forwards; }
        .animate-race-line { animation: race-line 0.4s linear infinite; }
        .animate-pulse-fast { animation: pulse 0.1s linear infinite; }
        @keyframes pulse { 0% { opacity: 0.95; } 100% { opacity: 1; } }
      `}</style>
    </div>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
import { Student, Question, StudentAnswer } from '../types';

interface SetupFormProps {
  lap: 1 | 2 | 3 | 4;
  setLap: (lap: any) => void;
  students: Student[];
  setStudents: (s: Student[]) => void;
  questions: Question[];
  setQuestions: (q: Question[] | ((prev: Question[]) => Question[])) => void;
  onProcess: (answers: StudentAnswer[]) => void;
}

export const SetupForm: React.FC<SetupFormProps> = ({
  lap, setLap, students, setStudents, questions, setQuestions, onProcess
}) => {
  const [qCount, setQCount] = useState(10);
  const [selectedPoint, setSelectedPoint] = useState(5);
  const [isDragging, setIsDragging] = useState(false);
  const [showBulkPaste, setShowBulkPaste] = useState(false);
  const [bulkInput, setBulkInput] = useState("");

  const handleStudentUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    const reader = new FileReader();
    reader.onload = (event) => {
      const csvLines = (event.target?.result as string).trim().split('\n');
      const parsed = csvLines.slice(1).map(line => {
        const [grade, cls, num, name] = line.split(',').map(s => s.trim());
        if (!grade || !cls || !num) return null;
        const paddedNum = num.padStart(2, '0');
        const id = `${grade}${cls}${paddedNum}`;
        return { 
          id, 
          name: name || `生徒 ${paddedNum}`, 
          class: `${grade}年${cls}組` 
        };
      }).filter((s): s is Student => s !== null);
      setStudents(parsed);
    };
    reader.readAsText(file);
  };

  const downloadStudentTemplate = () => {
    const bom = new Uint8Array([0xEF, 0xBB, 0xBF]);
    const csvContent = "grade,class,number,name\n1,A,01,山田 太郎\n1,A,02,佐藤 花子";
    const blob = new Blob([bom, csvContent], { type: 'text/csv;charset=utf-8' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url; a.download = 'driver_entry_template.csv'; a.click();
  };

  useEffect(() => {
    if (lap === 2 && questions.length === 0) {
      const initQ = Array.from({ length: qCount }, (_, i) => ({
        number: i + 1, correctAnswer: '', point: 5
      }));
      setQuestions(initQ);
    }
  }, [lap, qCount, questions.length, setQuestions]);

  const updateQ = (no: number, field: keyof Question, val: any) => {
    setQuestions((prev: Question[]) => prev.map(q => q.number === no ? { ...q, [field]: val } : q));
  };

  const handleBulkApply = () => {
    const chars = bulkInput.replace(/\s/g, '').split('');
    setQuestions((prev: Question[]) => prev.map((q, i) => ({
      ...q,
      correctAnswer: chars[i] ? chars[i].toUpperCase() : q.correctAnswer
    })));
    setShowBulkPaste(false);
    setBulkInput("");
  };

  const handleCellEnter = (no: number) => {
    if (isDragging) {
      updateQ(no, 'point', selectedPoint);
    }
  };

  const handlePointChange = (val: string) => {
    const num = parseInt(val);
    if (!isNaN(num)) {
      setSelectedPoint(Math.min(Math.max(num, 1), 100));
    }
  };

  const downloadAnswersTemplate = () => {
    const bom = new Uint8Array([0xEF, 0xBB, 0xBF]);
    const headers = ["student_id", ...questions.map(q => `Q${q.number}`)].join(',');
    const rows = students.map(s => `${s.id},${questions.map(() => "").join(',')}`).join('\n');
    const csvContent = `${headers}\n${rows}`;
    const blob = new Blob([bom, csvContent], { type: 'text/csv;charset=utf-8' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url; a.download = 'telemetry_upload_sheet.csv'; a.click();
  };

  const handleFinalUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    const reader = new FileReader();
    reader.onload = (event) => {
      const lines = (event.target?.result as string).trim().split('\n');
      const answers: StudentAnswer[] = lines.slice(1).map(line => {
        const parts = line.split(',').map(s => s.trim());
        const ans: Record<number, string> = {};
        questions.forEach((q, idx) => {
          ans[q.number] = parts[idx + 1] || "";
        });
        return { studentId: parts[0], answers: ans };
      });
      onProcess(answers);
    };
    reader.readAsText(file);
  };

  return (
    <div className="flex-1 flex flex-col space-y-8" onMouseUp={() => setIsDragging(false)}>
      {lap === 1 && (
        <div className="max-w-4xl mx-auto w-full space-y-8">
           <div className="bg-[#1f1f27] p-8 rounded border-b-4 border-[#e10600]">
              <h2 className="f1-font text-3xl font-black italic mb-2 uppercase">Lap 1: Driver Entry</h2>
              <p className="text-white/40 mb-8 uppercase text-xs font-bold tracking-widest">ドライバー名簿（学年,クラス,番号,氏名）をCSVで登録してください</p>

              <div className="grid grid-cols-2 gap-8">
                <button onClick={downloadStudentTemplate} className="h-40 border-2 border-dashed border-white/10 rounded flex flex-col items-center justify-center hover:bg-white/5 transition-all group">
                   <i className="fa-solid fa-file-csv text-5xl text-white/20 group-hover:text-white transition-all mb-4"></i>
                   <span className="f1-font text-sm italic font-bold">1. TEMPLATE DOWNLOAD</span>
                </button>
                <div className="h-40 border-2 border-dashed border-white/10 rounded flex flex-col items-center justify-center relative hover:bg-white/5 transition-all">
                   <input type="file" accept=".csv" onChange={handleStudentUpload} className="absolute inset-0 opacity-0 cursor-pointer" />
                   <i className="fa-solid fa-cloud-arrow-up text-5xl text-[#e10600] mb-4"></i>
                   <span className="f1-font text-sm italic font-bold">2. UPLOAD CSV</span>
                </div>
              </div>

              {students.length > 0 && (
                <div className="mt-8 flex items-center justify-between bg-[#00ffd2]/10 p-4 rounded border border-[#00ffd2]/30">
                   <div className="flex flex-col">
                      <span className="f1-font font-black italic text-[#00ffd2] uppercase leading-none">{students.length} 名を登録済み</span>
                   </div>
                   <button onClick={() => setLap(2)} className="f1-font bg-[#00ffd2] text-black px-12 py-3 font-black italic rounded skew-x-[-10deg] shadow-[0_0_15px_rgba(0,255,210,0.3)] hover:scale-110 transition-transform">
                      TECH SETUP へ進む <i className="fa-solid fa-chevron-right ml-2"></i>
                   </button>
                </div>
              )}
           </div>
        </div>
      )}

      {lap === 2 && (
        <div className="flex-1 flex flex-col overflow-hidden">
           <div className="bg-[#1f1f27] p-6 rounded-t border-b border-white/10 flex items-center justify-between no-print">
              <div className="flex items-center space-x-4">
                 <button onClick={() => setLap(1)} className="w-10 h-10 rounded-full border border-white/20 flex items-center justify-center hover:bg-white/5 transition-colors text-white/60 hover:text-white">
                    <i className="fa-solid fa-arrow-left"></i>
                 </button>
                 <div>
                    <h2 className="f1-font text-2xl font-black italic uppercase">Lap 2: Technical Setup</h2>
                    <p className="text-white/40 uppercase text-[10px] font-bold tracking-widest">問題数・正解・配点を設定してください</p>
                 </div>
              </div>
              <div className="flex items-center space-x-6">
                <button 
                  onClick={() => setShowBulkPaste(true)}
                  className="bg-white/5 hover:bg-white/10 border border-white/20 text-white px-4 py-1 text-xs font-bold f1-font italic rounded transition-colors"
                >
                  <i className="fa-solid fa-paste mr-2"></i>正解を一括入力
                </button>
                <div className="h-8 w-px bg-white/10"></div>
                <div className="flex items-center space-x-2">
                  <span className="text-[10px] font-bold text-white/40 uppercase">問題数:</span>
                  <input 
                    type="number" min="1" value={qCount} onChange={(e) => {
                      const val = parseInt(e.target.value);
                      if (isNaN(val) || val < 1) return;
                      setQCount(val);
                      setQuestions(Array.from({ length: val }, (_, i) => ({ number: i + 1, correctAnswer: '', point: selectedPoint })));
                    }}
                    className="bg-black/60 border border-white/20 text-white w-16 p-1 f1-font text-center font-bold outline-none"
                  />
                </div>
                <div className="h-8 w-px bg-white/10"></div>
                <div className="flex items-center space-x-2">
                  <span className="text-[10px] font-bold text-white/40 uppercase">配点:</span>
                  <input 
                    type="number" min="1" value={selectedPoint}
                    onChange={(e) => handlePointChange(e.target.value)}
                    className="bg-[#e10600] border-none text-white w-12 p-1 f1-font text-center font-bold outline-none"
                  />
                  <div className="flex space-x-1 ml-2">
                    {[1, 2, 3, 5, 10].map(p => (
                      <button 
                        key={p} onClick={() => setSelectedPoint(p)}
                        className={`w-8 h-8 rounded-sm f1-font text-[10px] font-bold border transition-all ${selectedPoint === p ? 'bg-white text-black border-white' : 'border-white/20 text-white/40 hover:text-white'}`}
                      >
                        {p}
                      </button>
                    ))}
                  </div>
                </div>
                <button onClick={() => setLap(3)} className="f1-font bg-[#e10600] text-white px-8 py-2 font-black italic rounded skew-x-[-10deg]">NEXT LAP</button>
              </div>
           </div>

           <div className="flex-1 overflow-y-auto bg-black/20 p-6 no-print">
              <div className="grid grid-cols-2 md:grid-cols-5 lg:grid-cols-10 gap-2">
                 {questions.map(q => (
                   <div key={q.number} className="bg-[#1f1f27] border border-white/10 rounded overflow-hidden">
                      <div className="bg-white/5 p-1 text-center text-[10px] f1-font font-black italic text-white/40 border-b border-white/5 uppercase">Q{q.number}</div>
                      <div className="p-2 space-y-2">
                         <input 
                           type="text" maxLength={1} value={q.correctAnswer} 
                           onChange={(e) => updateQ(q.number, 'correctAnswer', e.target.value.toUpperCase())}
                           className="w-full bg-black border border-white/10 rounded p-1 text-center font-black f1-font text-[#00ffd2] outline-none"
                         />
                         <div 
                           onMouseDown={() => { setIsDragging(true); updateQ(q.number, 'point', selectedPoint); }}
                           onMouseEnter={() => handleCellEnter(q.number)}
                           className="cursor-pointer bg-white/5 rounded py-1 text-center text-xs font-black f1-font text-white border border-white/5 select-none"
                         >
                           {q.point}
                         </div>
                      </div>
                   </div>
                 ))}
              </div>
           </div>

           {/* Bulk Paste Modal */}
           {showBulkPaste && (
             <div className="fixed inset-0 z-[200] flex items-center justify-center p-4 bg-black/80 backdrop-blur-md">
                <div className="bg-[#1f1f27] w-full max-w-lg rounded border-b-4 border-[#00ffd2] overflow-hidden">
                   <div className="p-6 border-b border-white/10 flex justify-between items-center">
                      <h3 className="f1-font font-black italic text-xl uppercase">Bulk Paste Telemetry</h3>
