      <th className="py-2 text-[10px] font-black text-slate-600">正解</th>
      <th className="py-2 text-[10px] font-black text-slate-600">あなたの解答</th>
      <th className="py-2 text-[10px] font-black text-slate-600 text-center">判定</th>
      <th className="py-2 text-[10px] font-black text-slate-600 text-right">全体正答率</th>
    </tr>
  );

  // 1行分のデータ要素
  const TableRow = ({ d }: { d: any }) => (
    <tr className="border-b border-slate-100 hover:bg-slate-50">
      <td className="py-2 font-black italic text-slate-800 text-xs">{d.questionNumber}</td>
      <td className="py-2 font-bold text-blue-600 text-xs">{d.correctAnswer}</td>
      <td className={`py-2 font-bold text-xs ${d.isCorrect ? 'text-slate-900' : 'text-[#e10600]'}`}>
        {d.studentAnswer || "-"}
      </td>
      <td className="py-2 text-center text-xs">
        {d.isCorrect ? (
          <span className="text-green-600 font-bold">○</span>
        ) : (
          <span className="text-[#e10600] font-bold">×</span>
        )}
      </td>
      <td className="py-2 text-right text-slate-400 font-mono text-[9px]">
        {d.overallAccuracy !== undefined ? `${d.overallAccuracy.toFixed(0)}%` : "-"}
      </td>
    </tr>
  );

  return (
    <div className="w-full max-w-[210mm] mx-auto bg-white text-black shadow-2xl p-0 overflow-hidden border-b-8 border-[#e10600] print:shadow-none print:border-none print:m-0">
      {/* 日本語メインのヘッダー */}
