         <div className="bg-[#e10600] text-white px-6 py-2 f1-font text-2xl font-black italic skew-x-[-15deg] mr-8 print:mr-4">
            {result.student.id}
         </div>
         <div className="flex-1">
            <h2 className="text-2xl font-black text-white mb-0 tracking-tight">
              {result.student.name} 様
            </h2>
            <div className="text-[#00ffd2] font-bold text-[10px] tracking-widest uppercase">{result.student.class} // 個人成績詳細レポート</div>
         </div>
         <div className="text-right">
            <div className="f1-font text-3xl font-black italic text-white print:text-black">
              {result.accuracy >= 80 ? 'EXCELLENT' : result.accuracy >= 60 ? 'GOOD' : 'RETRY'}
            </div>
         </div>
      </div>

      <div className="p-8 space-y-8 min-h-[260mm] print:p-4 print:space-y-4">
        {/* 統計グリッド */}
        <div className="grid grid-cols-4 gap-4 print:gap-2">
           {[
             { label: '総合得点', val: `${result.score} 点`, sub: `満点: ${result.totalPoints}`, color: 'text-slate-900' },
             { label: '正答率', val: `${result.accuracy.toFixed(1)}%`, color: 'text-[#e10600]' },
             { label: '正解数', val: `${result.details.filter(d => d.isCorrect).length} 問`, sub: `全 ${result.details.length} 問`, color: 'text-slate-900' },
             { label: '平均正答率', val: `${(result.details.reduce((acc, d) => acc + (d.overallAccuracy || 0), 0) / result.details.length).toFixed(1)}%`, sub: '全体平均', color: 'text-slate-500' }
           ].map((stat, i) => (
             <div key={i} className="bg-slate-50 p-3 border-l-4 border-slate-200">
                <p className="text-[9px] font-black text-slate-500 uppercase tracking-widest mb-1">{stat.label}</p>
