          )}
        </div>

        {/* 視覚的フィードバック */}
        <div className="bg-slate-50 p-4 border border-slate-200">
          <div className="flex justify-between items-center mb-2">
             <span className="text-[10px] font-black tracking-widest text-slate-500 uppercase">解答状況ビジュアライザー</span>
             <span className="text-[8px] font-black text-slate-400">ANALYSIS COMPLETE</span>
          </div>
          <div className="flex h-2 gap-0.5">
            {result.details.map((d, i) => (
              <div key={i} className={`flex-1 ${d.isCorrect ? 'bg-green-400' : 'bg-[#e10600]'}`} />
            ))}
          </div>
        </div>

        {/* フッター */}
        <div className="flex justify-between items-end pt-4 border-t border-slate-200 mt-auto">
           <div className="text-[8px] text-slate-300 italic font-bold">
             GRADED BY SMARTGRADER // SYSTEM VERIFIED // F1 ENGINE EDITION
           </div>
           <div className="bg-slate-800 text-white px-4 py-1 f1-font font-black italic text-[10px] skew-x-[-10deg] print:text-black print:bg-transparent">
             OFFICIAL RESULT
