      id: Date.now().toString(),
      timestamp: new Date().toLocaleString(),
      name: finalTitle,
      results: newResults,
      questions,
      students
    };
    const updated = [archive, ...archives];
    setArchives(updated);
    localStorage.setItem('grader_archives', JSON.stringify(updated));
  };

  const deleteArchive = (id: string) => {
    const updated = archives.filter(a => a.id !== id);
    setArchives(updated);
    localStorage.setItem('grader_archives', JSON.stringify(updated));
  };

  const loadArchive = (archive: ArchiveData) => {
    setStudents(archive.students);
    setQuestions(archive.questions);
    setResults(archive.results);
    setSessionTitle(archive.name);
    setSelectedResultIndex(0);
    triggerLapChange(4);
  };

  const handleProcessAnswers = (answers: StudentAnswer[]) => {
    const correctCounts: Record<number, number> = {};
    questions.forEach(q => correctCounts[q.number] = 0);

    answers.forEach(ans => {
      questions.forEach(q => {
        if (ans.answers[q.number] === q.correctAnswer) {
          correctCounts[q.number]++;
        }
      });
    });

    const totalStudents = answers.length;
    const newResults: ScoringResult[] = answers.map(ans => {
      const student = students.find(s => s.id === ans.studentId) || { id: ans.studentId, name: '未登録', class: '-' };
      let totalPoints = 0;
      let score = 0;
      const details = questions.map(q => {
        const studentAns = ans.answers[q.number] || "";
        const isCorrect = studentAns === q.correctAnswer;
        totalPoints += q.point;
        if (isCorrect) score += q.point;

        const overallAccuracy = totalStudents > 0 ? (correctCounts[q.number] / totalStudents) * 100 : 0;

        return { 
          questionNumber: q.number, 
          correctAnswer: q.correctAnswer, 
          studentAnswer: studentAns, 
          isCorrect, 
          point: q.point,
          overallAccuracy 
        };
      });
      return { student, score, totalPoints, accuracy: totalPoints > 0 ? (score / totalPoints) * 100 : 0, details };
    });

    const sorted = newResults.sort((a, b) => a.student.id.localeCompare(b.student.id));
    setResults(sorted);
    saveToArchive(sorted);
    triggerLapChange(4);
  };

  const resetAll = () => {
    setStudents([]);
    setQuestions([]);
    setResults([]);
    setSessionTitle("");
    triggerLapChange(1);
  };

  const nextDriver = () => {
    setSelectedResultIndex((prev) => (prev + 1) % results.length);
  };

  const prevDriver = () => {
    setSelectedResultIndex((prev) => (prev - 1 + results.length) % results.length);
  };

  return (
    <div className={`min-h-screen flex flex-col overflow-hidden relative ${isAnimating ? 'animate-pulse-fast' : ''}`}>
      {isAnimating && (
        <div className="fixed inset-0 z-[100] pointer-events-none overflow-hidden flex items-center justify-center">
          <div className="absolute inset-0 bg-black/40 backdrop-blur-sm transition-opacity duration-300"></div>
          <div className="relative w-full h-32 bg-[#e10600] skew-y-[-5deg] flex items-center justify-center animate-slide-across shadow-[0_0_100px_rgba(225,6,0,0.5)]">
             <div className="f1-font text-white text-6xl font-black italic tracking-tighter uppercase animate-bounce">BOX BOX BOX</div>
          </div>
          <div className="absolute right-full w-[200vw] h-1 bg-white/50 animate-race-line"></div>
        </div>
      )}

      <header className="no-print h-24 flex items-center px-12 bg-[#15151e] shrink-0 border-b border-white/5">
        <div className="border-4 border-white p-2 pr-12 rounded-tr-3xl rounded-bl-3xl flex items-center cursor-pointer" onClick={resetAll}>
          <span className="f1-font text-4xl font-black italic tracking-tighter text-white uppercase">Grader Graphics</span>
        </div>
        <div className="ml-12 flex flex-col">
           <div className="flex items-center space-x-2 mb-1">
              {[1, 2, 3, 4].map(l => (
                <div key={l} className={`h-1.5 w-12 skew-x-[-20deg] transition-all duration-500 ${lap >= l ? 'bg-[#e10600] shadow-[0_0_10px_#e10600]' : 'bg-white/10'}`}></div>
              ))}
              <span className="f1-font font-black italic ml-4 text-xs text-white/40">LAP {lap}/4</span>
           </div>
           {sessionTitle && <div className="text-[#00ffd2] font-black italic text-sm tracking-widest uppercase truncate max-w-[300px]">{sessionTitle}</div>}
        </div>

        <div className="ml-auto flex items-center space-x-4">
          {lap === 4 && (
            <div className="flex items-center space-x-4">
              <div className="flex items-center bg-[#2b2b36] border border-[#00ffd2] rounded overflow-hidden">
                <button onClick={prevDriver} className="px-4 py-2 hover:bg-[#00ffd2]/20 text-[#00ffd2] transition-colors border-r border-[#00ffd2]/30">
                  <i className="fa-solid fa-chevron-left"></i>
                </button>
                <select 
                  value={selectedResultIndex} 
                  onChange={(e) => setSelectedResultIndex(parseInt(e.target.value))}
                  className="bg-transparent text-white p-2 f1-font text-sm outline-none min-w-[240px] appearance-none text-center"
                >
                  {results.map((r, i) => (
                    <option key={r.student.id} value={i} className="bg-[#2b2b36]">
                      {r.student.class} {r.student.id.slice(-2)}番: {r.student.name}
                    </option>
                  ))}
                </select>
                <button onClick={nextDriver} className="px-4 py-2 hover:bg-[#00ffd2]/20 text-[#00ffd2] transition-colors border-l border-[#00ffd2]/30">
                  <i className="fa-solid fa-chevron-right"></i>
                </button>
              </div>

              <div className="relative">
                <button 
                  onClick={() => setIsPrintMenuOpen(!isPrintMenuOpen)}
                  className="f1-font bg-white text-black px-6 py-2 rounded font-black italic hover:bg-slate-200 transition-colors flex items-center"
                >
                  <i className="fa-solid fa-print mr-2"></i>PDF / 印刷 <i className="fa-solid fa-caret-down ml-2"></i>
                </button>
                {isPrintMenuOpen && (
                  <>
                    <div className="fixed inset-0 z-40" onClick={() => setIsPrintMenuOpen(false)}></div>
                    <div className="absolute top-full right-0 mt-2 w-56 bg-[#2b2b36] border border-white/10 rounded shadow-2xl z-50 overflow-hidden">
                      <button 
                        onClick={() => { setIsPrintMenuOpen(false); window.print(); }}
                        className="w-full text-left px-4 py-3 text-sm font-bold hover:bg-[#e10600] hover:text-white transition-colors flex items-center"
                      >
                        <i className="fa-solid fa-user mr-3 w-4"></i>現在の個票を印刷
                      </button>
                      <button 
                        onClick={() => { setIsPrintMenuOpen(false); document.body.classList.add('print-all'); window.print(); document.body.classList.remove('print-all'); }}
                        className="w-full text-left px-4 py-3 text-sm font-bold hover:bg-[#e10600] hover:text-white transition-colors flex items-center border-t border-white/5"
                      >
                        <i className="fa-solid fa-users mr-3 w-4"></i>全員分を一括印刷
                      </button>
                    </div>
                  </>
                )}
              </div>
              <button onClick={resetAll} className="f1-font bg-[#e10600] text-white px-6 py-2 rounded font-black italic hover:bg-red-700 transition-colors">終了</button>
            </div>
          )}
        </div>
      </header>

      <main className="flex-1 p-8 overflow-hidden flex flex-col relative">
        <div className="print-only-all hidden">
           {results.map((res, idx) => (
             <div key={res.student.id} className="page-break">
                <ResultReport result={res} />
             </div>
           ))}
        </div>

        <div className="flex-1 flex flex-col overflow-hidden result-display-area">
          {lap === 4 && results.length > 0 && (
            <div className="no-print absolute top-1/2 left-4 -translate-y-1/2 z-10">
               <button onClick={prevDriver} className="w-12 h-24 bg-black/50 hover:bg-[#e10600] text-white rounded-r-xl transition-all flex items-center justify-center border border-white/10 border-l-0">
                 <i className="fa-solid fa-chevron-left text-2xl"></i>
               </button>
            </div>
          )}
          {lap === 4 && results.length > 0 && (
            <div className="no-print absolute top-1/2 right-4 -translate-y-1/2 z-10">
               <button onClick={nextDriver} className="w-12 h-24 bg-black/50 hover:bg-[#e10600] text-white rounded-l-xl transition-all flex items-center justify-center border border-white/10 border-r-0">
                 <i className="fa-solid fa-chevron-right text-2xl"></i>
               </button>
            </div>
          )}

          {lap === 1 && (
            <div className="flex flex-col h-full space-y-6">
              <SetupForm 
                lap={1} setLap={triggerLapChange} students={students} setStudents={setStudents} 
                questions={questions} setQuestions={setQuestions} onProcess={handleProcessAnswers} 
                sessionTitle={sessionTitle} setSessionTitle={setSessionTitle}
              />
              {archives.length > 0 && (
                <div className="bg-[#1f1f27] p-6 rounded border border-white/10 no-print">
                  <h3 className="f1-font text-xl font-black italic text-white/40 mb-4 uppercase">Archive Records</h3>
                  <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4 max-h-60 overflow-y-auto pr-2">
                    {archives.map(a => (
                      <div key={a.id} className="bg-black/40 p-4 rounded flex flex-col justify-between border border-white/5 hover:border-[#e10600]/50 transition-colors">
                        <div>
                          <p className="font-bold text-sm text-[#00ffd2] mb-1 truncate">{a.name}</p>
                          <p className="text-[10px] text-white/40 uppercase font-black">{a.timestamp} // {a.results.length} DRIVERS</p>
                        </div>
                        <div className="flex space-x-2 mt-4">
                          <button onClick={() => loadArchive(a)} className="flex-1 text-[10px] font-black bg-white/10 text-white px-3 py-2 rounded hover:bg-white/20 transition-colors uppercase italic">LOAD</button>
                          <button onClick={() => deleteArchive(a.id)} className="text-[10px] font-black bg-[#e10600]/10 text-[#e10600] px-3 py-2 rounded hover:bg-[#e10600]/20 transition-colors uppercase italic">DEL</button>
                        </div>
                      </div>
                    ))}
                  </div>
                </div>
              )}
            </div>
          )}
          {lap > 1 && lap < 4 && (
             <SetupForm 
                lap={lap} setLap={triggerLapChange} students={students} setStudents={setStudents} 
                questions={questions} setQuestions={setQuestions} onProcess={handleProcessAnswers}
                sessionTitle={sessionTitle} setSessionTitle={setSessionTitle}
              />
          )}
          {lap === 4 && results[selectedResultIndex] && (
            <div className="flex-1 overflow-y-auto px-12 pb-12 single-print-view">
              <ResultReport result={results[selectedResultIndex]} />
            </div>
          )}
        </div>
      </main>

      <footer className="h-14 bg-[#15151e] border-t border-white/10 flex items-center px-8 no-print shrink-0">
        <div className="bg-white p-1 px-4 text-black font-black italic mr-4 f1-font">FIA</div>
        <div className="flex-1 text-sm font-bold tracking-tight overflow-hidden whitespace-nowrap">
           <span className="inline-block animate-[marquee_20s_linear_infinite] uppercase text-white/60">
             {lap === 1 && "ドライバー登録: セッションタイトルを入力し、CSVをアップロードするかアーカイブを選択してください"}
             {lap === 2 && "テクニカル設定: 問題数と正答、配点を設定してください（一括ペースト対応）"}
             {lap === 3 && "データ解析: 完了済み解答データをアップロードして最終解析を開始します"}
             {lap === 4 && "ポストレースレポート: 印刷オプションから個別または一括でのPDF出力が可能です"}
           </span>
        </div>
      </footer>
      <style>{`
        @keyframes marquee { 0% { transform: translateX(100%); } 100% { transform: translateX(-100%); } }
        @keyframes slide-across {
          0% { transform: translateX(-150%) skewY(-5deg); }
          50% { transform: translateX(0) skewY(-5deg); }
          100% { transform: translateX(150%) skewY(-5deg); }
        }
        @keyframes race-line {
          0% { left: -100%; width: 0%; opacity: 1; }
          100% { left: 100%; width: 200%; opacity: 0; }
        }
        .animate-slide-across { animation: slide-across 0.8s cubic-bezier(0.7, 0, 0.3, 1) forwards; }
        .animate-race-line { animation: race-line 0.4s linear infinite; }
        .animate-pulse-fast { animation: pulse 0.1s linear infinite; }
        @keyframes pulse { 0% { opacity: 0.95; } 100% { opacity: 1; } }

        @media print {
          body.print-all .single-print-view { display: none !important; }
          body.print-all .print-only-all { display: block !important; }
          .page-break { page-break-after: always; }
          .result-display-area { overflow: visible !important; height: auto !important; }
        }
      `}</style>
    </div>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
import { Student, Question, StudentAnswer } from '../types';

interface SetupFormProps {
  lap: 1 | 2 | 3 | 4;
  setLap: (lap: any) => void;
  students: Student[];
  setStudents: (s: Student[]) => void;
  questions: Question[];
  setQuestions: (q: Question[] | ((prev: Question[]) => Question[])) => void;
  onProcess: (answers: StudentAnswer[]) => void;
  sessionTitle: string;
  setSessionTitle: (t: string) => void;
}

export const SetupForm: React.FC<SetupFormProps> = ({
  lap, setLap, students, setStudents, questions, setQuestions, onProcess,
  sessionTitle, setSessionTitle
}) => {
  const [qCount, setQCount] = useState(10);
  const [selectedPoint, setSelectedPoint] = useState(5);
  const [isDragging, setIsDragging] = useState(false);
  const [showBulkPaste, setShowBulkPaste] = useState(false);
  const [bulkInput, setBulkInput] = useState("");

  const handleStudentUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    const reader = new FileReader();
    reader.onload = (event) => {
      const csvLines = (event.target?.result as string).trim().split('\n');
      const parsed = csvLines.slice(1).map(line => {
        const [grade, cls, num, name] = line.split(',').map(s => s.trim());
        if (!grade || !cls || !num) return null;
        const paddedNum = num.padStart(2, '0');
        const id = `${grade}${cls}${paddedNum}`;
        return { 
          id, 
          name: name || `生徒 ${paddedNum}`, 
          class: `${grade}年${cls}組` 
        };
      }).filter((s): s is Student => s !== null);
      setStudents(parsed);
    };
    reader.readAsText(file);
  };

  const downloadStudentTemplate = () => {
    const bom = new Uint8Array([0xEF, 0xBB, 0xBF]);
    const csvContent = "grade,class,number,name\n1,A,01,山田 太郎\n1,A,02,佐藤 花子";
    const blob = new Blob([bom, csvContent], { type: 'text/csv;charset=utf-8' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url; a.download = 'driver_entry_template.csv'; a.click();
  };

  useEffect(() => {
    if (lap === 2 && questions.length === 0) {
      const initQ = Array.from({ length: qCount }, (_, i) => ({
        number: i + 1, correctAnswer: '', point: 5
      }));
      setQuestions(initQ);
    }
  }, [lap, qCount, questions.length, setQuestions]);

  const updateQ = (no: number, field: keyof Question, val: any) => {
    setQuestions((prev: Question[]) => prev.map(q => q.number === no ? { ...q, [field]: val } : q));
  };

  const handleBulkApply = () => {
    const chars = bulkInput.replace(/\s/g, '').split('');
    setQuestions((prev: Question[]) => prev.map((q, i) => ({
      ...q,
      correctAnswer: chars[i] ? chars[i].toUpperCase() : q.correctAnswer
    })));
    setShowBulkPaste(false);
    setBulkInput("");
  };

  const handleCellEnter = (no: number) => {
    if (isDragging) {
      updateQ(no, 'point', selectedPoint);
    }
  };

  const handlePointChange = (val: string) => {
    const num = parseInt(val);
    if (!isNaN(num)) {
      setSelectedPoint(Math.min(Math.max(num, 1), 100));
    }
  };

  const downloadAnswersTemplate = () => {
    const bom = new Uint8Array([0xEF, 0xBB, 0xBF]);
    const headers = ["student_id", ...questions.map(q => `Q${q.number}`)].join(',');
    const rows = students.map(s => `${s.id},${questions.map(() => "").join(',')}`).join('\n');
    const csvContent = `${headers}\n${rows}`;
    const blob = new Blob([bom, csvContent], { type: 'text/csv;charset=utf-8' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url; a.download = 'telemetry_upload_sheet.csv'; a.click();
  };

  const handleFinalUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    const reader = new FileReader();
    reader.onload = (event) => {
      const lines = (event.target?.result as string).trim().split('\n');
      const answers: StudentAnswer[] = lines.slice(1).map(line => {
        const parts = line.split(',').map(s => s.trim());
        const ans: Record<number, string> = {};
        questions.forEach((q, idx) => {
          ans[q.number] = parts[idx + 1] || "";
        });
        return { studentId: parts[0], answers: ans };
      });
      onProcess(answers);
    };
    reader.readAsText(file);
  };

  return (
    <div className="flex-1 flex flex-col space-y-8" onMouseUp={() => setIsDragging(false)}>
      {lap === 1 && (
        <div className="max-w-4xl mx-auto w-full space-y-8">
           <div className="bg-[#1f1f27] p-8 rounded border-b-4 border-[#e10600]">
              <h2 className="f1-font text-3xl font-black italic mb-2 uppercase">Lap 1: Driver Entry</h2>
              <div className="mb-8 space-y-4">
                 <label className="text-white/40 uppercase text-xs font-bold tracking-widest block">セッションタイトル設定</label>
                 <input 
                   type="text" 
                   value={sessionTitle} 
                   onChange={(e) => setSessionTitle(e.target.value)}
                   placeholder="例：2024年度 第1回 実力テスト"
                   className="w-full bg-black border border-white/10 rounded p-4 text-white f1-font text-lg focus:border-[#00ffd2] transition-colors outline-none"
                 />
              </div>

              <div className="grid grid-cols-2 gap-8 mt-12">
                <button onClick={downloadStudentTemplate} className="h-40 border-2 border-dashed border-white/10 rounded flex flex-col items-center justify-center hover:bg-white/5 transition-all group">
                   <i className="fa-solid fa-file-csv text-5xl text-white/20 group-hover:text-white transition-all mb-4"></i>
                   <span className="f1-font text-sm italic font-bold uppercase tracking-tight">1. TEMPLATE DOWNLOAD</span>
                </button>
                <div className="h-40 border-2 border-dashed border-white/10 rounded flex flex-col items-center justify-center relative hover:bg-white/5 transition-all">
                   <input type="file" accept=".csv" onChange={handleStudentUpload} className="absolute inset-0 opacity-0 cursor-pointer" />
                   <i className="fa-solid fa-cloud-arrow-up text-5xl text-[#e10600] mb-4"></i>
                   <span className="f1-font text-sm italic font-bold uppercase tracking-tight">2. UPLOAD DRIVER CSV</span>
                </div>
              </div>

              {students.length > 0 && (
                <div className="mt-8 flex items-center justify-between bg-[#00ffd2]/10 p-4 rounded border border-[#00ffd2]/30 animate-pulse">
                   <div className="flex flex-col">
                      <span className="f1-font font-black italic text-[#00ffd2] uppercase leading-none">{students.length} DRIVERS REGISTERED</span>
                   </div>
                   <button onClick={() => setLap(2)} className="f1-font bg-[#00ffd2] text-black px-12 py-3 font-black italic rounded skew-x-[-10deg] shadow-[0_0_15px_rgba(0,255,210,0.3)] hover:scale-110 transition-transform">
                      GO TO TECH SETUP <i className="fa-solid fa-chevron-right ml-2"></i>
                   </button>
                </div>
              )}
           </div>
        </div>
      )}

      {lap === 2 && (
        <div className="flex-1 flex flex-col overflow-hidden">
           <div className="bg-[#1f1f27] p-6 rounded-t border-b border-white/10 flex items-center justify-between no-print">
              <div className="flex items-center space-x-4">
                 <button onClick={() => setLap(1)} className="w-10 h-10 rounded-full border border-white/20 flex items-center justify-center hover:bg-white/5 transition-colors text-white/60 hover:text-white">
                    <i className="fa-solid fa-arrow-left"></i>
                 </button>
                 <div>
                    <h2 className="f1-font text-2xl font-black italic uppercase">Lap 2: Technical Setup</h2>
                    <p className="text-white/40 uppercase text-[10px] font-bold tracking-widest">問題数・正解・配点を設定してください</p>
                 </div>
              </div>
              <div className="flex items-center space-x-6">
                <button 
                  onClick={() => setShowBulkPaste(true)}
                  className="bg-white/5 hover:bg-white/10 border border-white/20 text-white px-4 py-1 text-xs font-bold f1-font italic rounded transition-colors"
                >
                  <i className="fa-solid fa-paste mr-2"></i>正解を一括入力
                </button>
                <div className="h-8 w-px bg-white/10"></div>
                <div className="flex items-center space-x-2">
                  <span className="text-[10px] font-bold text-white/40 uppercase">問題数:</span>
                  <input 
                    type="number" min="1" value={qCount} onChange={(e) => {
                      const val = parseInt(e.target.value);
                      if (isNaN(val) || val < 1) return;
                      setQCount(val);
                      setQuestions(Array.from({ length: val }, (_, i) => ({ number: i + 1, correctAnswer: '', point: selectedPoint })));
                    }}
                    className="bg-black/60 border border-white/20 text-white w-16 p-1 f1-font text-center font-bold outline-none"
                  />
                </div>
                <div className="h-8 w-px bg-white/10"></div>
                <div className="flex items-center space-x-2">
                  <span className="text-[10px] font-bold text-white/40 uppercase">配点:</span>
                  <input 
                    type="number" min="1" value={selectedPoint}
                    onChange={(e) => handlePointChange(e.target.value)}
                    className="bg-[#e10600] border-none text-white w-12 p-1 f1-font text-center font-bold outline-none"
                  />
                  <div className="flex space-x-1 ml-2">
                    {[1, 2, 3, 5, 10].map(p => (
                      <button 
                        key={p} onClick={() => setSelectedPoint(p)}
                        className={`w-8 h-8 rounded-sm f1-font text-[10px] font-bold border transition-all ${selectedPoint === p ? 'bg-white text-black border-white' : 'border-white/20 text-white/40 hover:text-white'}`}
                      >
                        {p}
                      </button>
                    ))}
                  </div>
                </div>
                <button onClick={() => setLap(3)} className="f1-font bg-[#e10600] text-white px-8 py-2 font-black italic rounded skew-x-[-10deg]">NEXT LAP</button>
              </div>
           </div>

           <div className="flex-1 overflow-y-auto bg-black/20 p-6 no-print">
              <div className="grid grid-cols-2 md:grid-cols-5 lg:grid-cols-10 gap-2">
                 {questions.map(q => (
                   <div key={q.number} className="bg-[#1f1f27] border border-white/10 rounded overflow-hidden">
                      <div className="bg-white/5 p-1 text-center text-[10px] f1-font font-black italic text-white/40 border-b border-white/5 uppercase">Q{q.number}</div>
                      <div className="p-2 space-y-2">
                         <input 
                           type="text" maxLength={1} value={q.correctAnswer} 
                           onChange={(e) => updateQ(q.number, 'correctAnswer', e.target.value.toUpperCase())}
                           className="w-full bg-black border border-white/10 rounded p-1 text-center font-black f1-font text-[#00ffd2] outline-none"
                         />
                         <div 
                           onMouseDown={() => { setIsDragging(true); updateQ(q.number, 'point', selectedPoint); }}
                           onMouseEnter={() => handleCellEnter(q.number)}
                           className="cursor-pointer bg-white/5 rounded py-1 text-center text-xs font-black f1-font text-white border border-white/5 select-none"
                         >
                           {q.point}
                         </div>
                      </div>
                   </div>
                 ))}
              </div>
           </div>

           {showBulkPaste && (
             <div className="fixed inset-0 z-[200] flex items-center justify-center p-4 bg-black/80 backdrop-blur-md">
                <div className="bg-[#1f1f27] w-full max-w-lg rounded border-b-4 border-[#00ffd2] overflow-hidden shadow-[0_0_100px_rgba(0,255,210,0.2)]">
                   <div className="p-6 border-b border-white/10 flex justify-between items-center bg-[#15151e]">
                      <h3 className="f1-font font-black italic text-xl uppercase tracking-tighter">Bulk Paste Telemetry</h3>
                      <button onClick={() => setShowBulkPaste(false)} className="text-white/40 hover:text-white"><i className="fa-solid fa-xmark"></i></button>
                   </div>
                   <div className="p-6">
                      <p className="text-xs text-white/60 mb-4 uppercase font-bold tracking-widest">正解文字列を貼り付けてください</p>
                      <textarea 
                        value={bulkInput}
                        onChange={(e) => setBulkInput(e.target.value)}
                        className="w-full h-32 bg-black border border-white/10 rounded p-4 text-[#00ffd2] font-mono text-xl outline-none focus:border-[#00ffd2] transition-colors"
                        placeholder="例: 12345ABCD..."
                        autoFocus
                      />
                      <div className="mt-6 flex justify-end space-x-4">
                        <button onClick={() => setShowBulkPaste(false)} className="px-6 py-2 f1-font text-xs italic font-bold text-white/40 hover:text-white uppercase">CANCEL</button>
                        <button onClick={handleBulkApply} className="bg-[#00ffd2] text-black px-8 py-2 f1-font text-xs italic font-black rounded skew-x-[-10deg]">APPLY DATA</button>
                      </div>
                   </div>
                </div>
             </div>
           )}
        </div>
      )}

      {lap === 3 && (
        <div className="max-w-4xl mx-auto w-full space-y-8">
           <div className="bg-[#1f1f27] p-8 rounded border-b-4 border-[#e10600]">
              <div className="flex items-center justify-between mb-8">
                <div className="flex items-center space-x-4">
                  <button onClick={() => setLap(2)} className="w-10 h-10 rounded-full border border-white/20 flex items-center justify-center hover:bg-white/5 transition-colors text-white/60 hover:text-white">
                    <i className="fa-solid fa-arrow-left"></i>
                  </button>
                  <h2 className="f1-font text-3xl font-black italic uppercase">Lap 3: Data Analysis</h2>
                </div>
              </div>
              <div className="grid grid-cols-2 gap-8">
                <button onClick={downloadAnswersTemplate} className="h-40 border-2 border-dashed border-white/10 rounded flex flex-col items-center justify-center hover:bg-white/5 transition-all group">
                   <i className="fa-solid fa-file-export text-4xl text-[#00ffd2] mb-2 group-hover:scale-110 transition-transform"></i>
                   <span className="f1-font text-sm italic font-bold uppercase tracking-tight">1. DOWNLOAD TELEMETRY SHEET</span>
                </button>
                <div className="h-40 border-2 border-dashed border-white/10 rounded flex flex-col items-center justify-center relative hover:bg-white/5 transition-all">
                   <input type="file" accept=".csv" onChange={handleFinalUpload} className="absolute inset-0 opacity-0 cursor-pointer" />
                   <i className="fa-solid fa-microchip text-4xl text-[#e10600] mb-2 group-hover:rotate-12 transition-transform"></i>
                   <span className="f1-font text-sm italic font-bold uppercase tracking-tight">2. UPLOAD COMPLETED DATA</span>
                </div>
              </div>
           </div>
        </div>
      )}
    </div>
  );
};

export interface Student {
  id: string;
  name: string;
  class: string;
}

export type Competency = '知識・技能' | '思考・判断・表現' | '主体性';

export interface Question {
  number: number;
  correctAnswer: string;
  point: number;
  section: string; // 大問
  competency: Competency; // 観点
}

export interface StudentAnswer {
  studentId: string;
  answers: Record<number, string>;
}

export interface ScoringResult {
  student: Student;
  score: number;
  totalPoints: number;
  accuracy: number;
  rank?: number;
  classRank?: number;
  details: {
    questionNumber: number;
    correctAnswer: string;
    studentAnswer: string;
    isCorrect: boolean;
    point: number;
    overallAccuracy?: number;
    section: string;
    competency: Competency;
  }[];
  competencyScores: Record<Competency, { score: number; total: number }>;
  sectionScores: Record<string, { score: number; total: number }>;
}

export interface ArchiveData {
  id: string;
  timestamp: string;
  name: string;
  results: ScoringResult[];
  questions: Question[];
  students: Student[];
}

import React, { useState, useEffect } from 'react';
import { Student, Question, StudentAnswer, ScoringResult, ArchiveData, Competency } from './types';
import { SetupForm } from './components/SetupForm';
import { ResultReport } from './components/ResultReport';
import { StatisticsView } from './components/StatisticsView';

const App: React.FC = () => {
  const [students, setStudents] = useState<Student[]>([]);
  const [questions, setQuestions] = useState<Question[]>([]);
  const [results, setResults] = useState<ScoringResult[]>([]);
  const [lap, setLap] = useState<1 | 2 | 3 | 4 | 5>(1);
  const [isAnimating, setIsAnimating] = useState(false);
  const [archives, setArchives] = useState<ArchiveData[]>([]);
  const [selectedResultIndex, setSelectedResultIndex] = useState<number>(0);
  const [sessionTitle, setSessionTitle] = useState<string>("");
  const [isPrintMenuOpen, setIsPrintMenuOpen] = useState(false);

  useEffect(() => {
    const saved = localStorage.getItem('grader_archives');
    if (saved) setArchives(JSON.parse(saved));
  }, []);

  const triggerLapChange = (nextLap: 1 | 2 | 3 | 4 | 5) => {
    setIsAnimating(true);
    setTimeout(() => {
      setLap(nextLap);
      setTimeout(() => setIsAnimating(false), 500);
    }, 400);
  };

  const calculateResults = (answers: StudentAnswer[]) => {
    const correctCounts: Record<number, number> = {};
    questions.forEach(q => correctCounts[q.number] = 0);

    answers.forEach(ans => {
      questions.forEach(q => {
        if (ans.answers[q.number] === q.correctAnswer) correctCounts[q.number]++;
      });
    });

    const totalStudents = answers.length;
    let newResults: ScoringResult[] = answers.map(ans => {
      const student = students.find(s => s.id === ans.studentId) || { id: ans.studentId, name: '未登録', class: '-' };
      let totalScore = 0;
      let totalPointsMax = 0;

      const compScores: Record<Competency, { score: number; total: number }> = {
        '知識・技能': { score: 0, total: 0 },
        '思考・判断・表現': { score: 0, total: 0 },
        '主体性': { score: 0, total: 0 }
      };
      const sectScores: Record<string, { score: number; total: number }> = {};

      const details = questions.map(q => {
        const studentAns = ans.answers[q.number] || "";
        const isCorrect = studentAns === q.correctAnswer;
        totalPointsMax += q.point;
        if (isCorrect) totalScore += q.point;

        // 観点別集計
        compScores[q.competency].total += q.point;
        if (isCorrect) compScores[q.competency].score += q.point;

        // 大問別集計
        if (!sectScores[q.section]) sectScores[q.section] = { score: 0, total: 0 };
        sectScores[q.section].total += q.point;
        if (isCorrect) sectScores[q.section].score += q.point;

        return { 
          questionNumber: q.number, 
          correctAnswer: q.correctAnswer, 
          studentAnswer: studentAns, 
          isCorrect, 
          point: q.point,
          overallAccuracy: totalStudents > 0 ? (correctCounts[q.number] / totalStudents) * 100 : 0,
          section: q.section,
          competency: q.competency
        };
      });

      return { 
        student, 
        score: totalScore, 
        totalPoints: totalPointsMax, 
        accuracy: totalPointsMax > 0 ? (totalScore / totalPointsMax) * 100 : 0, 
        details,
        competencyScores: compScores,
        sectionScores: sectScores
      };
    });

    // 順位付け (全体)
    newResults.sort((a, b) => b.score - a.score);
    newResults = newResults.map((r, i) => ({ ...r, rank: i + 1 }));

    // 順位付け (クラス内)
    const classes = Array.from(new Set(newResults.map(r => r.student.class)));
    classes.forEach(cls => {
      const clsResults = newResults.filter(r => r.student.class === cls).sort((a, b) => b.score - a.score);
      clsResults.forEach((r, i) => {
        const target = newResults.find(nr => nr.student.id === r.student.id);
        if (target) target.classRank = i + 1;
      });
    });

    return newResults.sort((a, b) => a.student.id.localeCompare(b.student.id));
  };

  const handleProcessAnswers = (answers: StudentAnswer[]) => {
    const finalResults = calculateResults(answers);
    setResults(finalResults);
    saveToArchive(finalResults);
    triggerLapChange(4);
  };

  const saveToArchive = (newResults: ScoringResult[]) => {
    const archive: ArchiveData = {
      id: Date.now().toString(),
      timestamp: new Date().toLocaleString(),
      name: sessionTitle || "無題のセッション",
      results: newResults,
      questions,
      students
    };
    const updated = [archive, ...archives];
    setArchives(updated);
    localStorage.setItem('grader_archives', JSON.stringify(updated));
  };

  const exportExcelData = () => {
    const bom = new Uint8Array([0xEF, 0xBB, 0xBF]);
    const sections = Array.from(new Set(questions.map(q => q.section))).sort();
    const competencies: Competency[] = ['知識・技能', '思考・判断・表現', '主体性'];

    let csv = "出席番号,氏名,クラス,合計点," + 
      sections.map(s => `大問${s}得点,大問${s}満点`).join(',') + "," +
      competencies.map(c => `${c}得点,${c}満点`).join(',') + "\n";

    results.forEach(r => {
      csv += `${r.student.id},${r.student.name},${r.student.class},${r.score},`;
      csv += sections.map(s => `${r.sectionScores[s]?.score || 0},${r.sectionScores[s]?.total || 0}`).join(',') + ",";
      csv += competencies.map(c => `${r.competencyScores[c]?.score || 0},${r.competencyScores[c]?.total || 0}`).join(',') + "\n";
    });

    const blob = new Blob([bom, csv], { type: 'text/csv;charset=utf-8' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url; a.download = `${sessionTitle}_成績一覧.csv`; a.click();
  };

  const resetAll = () => {
    setStudents([]); setQuestions([]); setResults([]); setSessionTitle(""); triggerLapChange(1);
  };

  return (
    <div className={`min-h-screen flex flex-col overflow-hidden relative ${isAnimating ? 'animate-pulse-fast' : ''}`}>
      {/* Animation elements omitted for brevity - same as before */}

      <header className="no-print h-24 flex items-center px-12 bg-[#15151e] shrink-0 border-b border-white/5">
        <div className="border-4 border-white p-2 pr-12 rounded-tr-3xl rounded-bl-3xl flex items-center cursor-pointer" onClick={resetAll}>
          <span className="f1-font text-4xl font-black italic tracking-tighter text-white uppercase">Grader Graphics</span>
        </div>
        <div className="ml-12 flex flex-col">
           <div className="flex items-center space-x-2 mb-1">
              {[1, 2, 3, 4, 5].map(l => (
                <div key={l} className={`h-1.5 w-10 skew-x-[-20deg] transition-all duration-500 ${lap >= l ? 'bg-[#e10600] shadow-[0_0_10px_#e10600]' : 'bg-white/10'}`}></div>
              ))}
              <span className="f1-font font-black italic ml-4 text-xs text-white/40">LAP {lap}/5</span>
           </div>
           {sessionTitle && <div className="text-[#00ffd2] font-black italic text-sm tracking-widest uppercase truncate max-w-[300px]">{sessionTitle}</div>}
        </div>

        <div className="ml-auto flex items-center space-x-4">
          {lap === 4 && (
            <>
              <div className="flex items-center bg-[#2b2b36] border border-[#00ffd2] rounded overflow-hidden">
                <button onClick={() => setSelectedResultIndex(p => (p - 1 + results.length) % results.length)} className="px-4 py-2 hover:bg-[#00ffd2]/20 text-[#00ffd2] border-r border-[#00ffd2]/30"><i className="fa-solid fa-chevron-left"></i></button>
                <select value={selectedResultIndex} onChange={(e) => setSelectedResultIndex(parseInt(e.target.value))} className="bg-transparent text-white p-2 f1-font text-sm outline-none min-w-[200px] appearance-none text-center">
                  {results.map((r, i) => <option key={r.student.id} value={i}>{r.student.name}</option>)}
                </select>
                <button onClick={() => setSelectedResultIndex(p => (p + 1) % results.length)} className="px-4 py-2 hover:bg-[#00ffd2]/20 text-[#00ffd2] border-l border-[#00ffd2]/30"><i className="fa-solid fa-chevron-right"></i></button>
              </div>
              <div className="relative">
                <button onClick={() => setIsPrintMenuOpen(!isPrintMenuOpen)} className="f1-font bg-white text-black px-6 py-2 rounded font-black italic hover:bg-slate-200 transition-colors flex items-center">
                  <i className="fa-solid fa-print mr-2"></i>PDF/印刷 <i className="fa-solid fa-caret-down ml-2"></i>
                </button>
                {isPrintMenuOpen && (
                  <div className="absolute top-full right-0 mt-2 w-56 bg-[#2b2b36] border border-white/10 rounded shadow-2xl z-50">
                    <button onClick={() => { setIsPrintMenuOpen(false); window.print(); }} className="w-full text-left px-4 py-3 text-sm font-bold hover:bg-[#e10600] hover:text-white transition-colors flex items-center">個別保存/印刷</button>
                    <button onClick={() => { setIsPrintMenuOpen(false); document.body.classList.add('print-all'); window.print(); document.body.classList.remove('print-all'); }} className="w-full text-left px-4 py-3 text-sm font-bold hover:bg-[#e10600] hover:text-white transition-colors border-t border-white/5 flex items-center">一括保存/印刷</button>
                  </div>
                )}
              </div>
              <button onClick={() => triggerLapChange(5)} className="f1-font bg-[#00ffd2] text-black px-6 py-2 rounded font-black italic hover:scale-105 transition-all">STATISTICS <i className="fa-solid fa-chart-line ml-2"></i></button>
            </>
          )}
          {lap === 5 && (
             <>
               <button onClick={exportExcelData} className="f1-font bg-white text-black px-6 py-2 rounded font-black italic hover:bg-slate-200"><i className="fa-solid fa-file-excel mr-2"></i>EXCEL出力</button>
               <button onClick={() => triggerLapChange(4)} className="f1-font border border-white/20 text-white px-6 py-2 rounded font-black italic hover:bg-white/5">BACK TO REPORT</button>
             </>
          )}
        </div>
      </header>

      <main className="flex-1 overflow-hidden flex flex-col relative">
        <div className="print-only-all hidden">
           {results.map((res) => <div key={res.student.id} className="page-break"><ResultReport result={res} title={sessionTitle} /></div>)}
        </div>

        <div className="flex-1 flex flex-col overflow-hidden p-8">
          {lap <= 3 && <SetupForm lap={lap as 1|2|3} setLap={triggerLapChange} students={students} setStudents={setStudents} questions={questions} setQuestions={setQuestions} onProcess={handleProcessAnswers} sessionTitle={sessionTitle} setSessionTitle={setSessionTitle} />}
          {lap === 4 && results[selectedResultIndex] && (
            <div className="flex-1 overflow-y-auto single-print-view"><ResultReport result={results[selectedResultIndex]} title={sessionTitle} /></div>
          )}
          {lap === 5 && <StatisticsView results={results} questions={questions} />}
        </div>
      </main>

      <footer className="h-12 bg-[#15151e] border-t border-white/10 flex items-center px-8 no-print text-[10px] text-white/40 uppercase font-black tracking-widest italic">
        SmartGrader Professional // Formula 1 Data Analytics Engine // Ver 3.5
      </footer>

      <style>{`
        @media print {
          body.print-all .single-print-view { display: none !important; }
          body.print-all .print-only-all { display: block !important; }
          .page-break { page-break-after: always; }
          @page { size: A4; margin: 0; }
        }
        .animate-pulse-fast { animation: pulse 0.1s linear infinite; }
      `}</style>
    </div>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
import { Student, Question, StudentAnswer, Competency } from '../types';

interface SetupFormProps {
  lap: 1 | 2 | 3;
  setLap: (lap: any) => void;
  students: Student[];
  setStudents: (s: Student[]) => void;
  questions: Question[];
  setQuestions: (q: Question[] | ((prev: Question[]) => Question[])) => void;
  onProcess: (answers: StudentAnswer[]) => void;
  sessionTitle: string;
  setSessionTitle: (t: string) => void;
}

const COMPETENCIES: Competency[] = ['知識・技能', '思考・判断・表現', '主体性'];

export const SetupForm: React.FC<SetupFormProps> = ({
  lap, setLap, students, setStudents, questions, setQuestions, onProcess,
  sessionTitle, setSessionTitle
}) => {
  const [qCount, setQCount] = useState(questions.length || 10);
  const [selectedPoint, setSelectedPoint] = useState(5);
  const [isDragging, setIsDragging] = useState(false);
  const [showBulkPaste, setShowBulkPaste] = useState(false);
  const [bulkInput, setBulkInput] = useState("");

  useEffect(() => {
    if (lap === 2 && questions.length === 0) {
      setQuestions(Array.from({ length: qCount }, (_, i) => ({
        number: i + 1, correctAnswer: '', point: 5, section: '1', competency: '知識・技能'
      })));
    }
  }, [lap]);

  const updateQ = (no: number, field: keyof Question, val: any) => {
    setQuestions((prev) => prev.map(q => q.number === no ? { ...q, [field]: val } : q));
  };

  return (
    <div className="flex-1 flex flex-col space-y-6" onMouseUp={() => setIsDragging(false)}>
      {lap === 1 && (
        <div className="max-w-3xl mx-auto w-full bg-[#1f1f27] p-8 rounded border-b-4 border-[#e10600]">
          <h2 className="f1-font text-3xl font-black italic mb-8 uppercase">Lap 1: Session Init</h2>
          <div className="space-y-6">
            <div>
              <label className="text-white/40 uppercase text-xs font-black mb-2 block tracking-widest">Test Title / テスト名</label>
              <input value={sessionTitle} onChange={(e) => setSessionTitle(e.target.value)} placeholder="例：学年末考査 数学A" className="w-full bg-black border border-white/10 rounded p-4 text-white f1-font text-lg focus:border-[#00ffd2] outline-none" />
            </div>
            <div className="grid grid-cols-2 gap-4">
              <div className="border-2 border-dashed border-white/10 p-6 rounded text-center hover:bg-white/5 transition-colors cursor-pointer relative">
                <input type="file" accept=".csv" onChange={(e) => {
                  const file = e.target.files?.[0]; if (!file) return;
                  const reader = new FileReader();
                  reader.onload = (ev) => {
                    const lines = (ev.target?.result as string).trim().split('\n');
                    const parsed = lines.slice(1).map(l => {
                      const [g, c, n, name] = l.split(',').map(s => s.trim());
                      return g ? { id: `${g}${c}${n.padStart(2,'0')}`, name: name || '生徒', class: `${g}年${c}組` } : null;
                    }).filter(s => s) as Student[];
                    setStudents(parsed);
                  };
                  reader.readAsText(file);
                }} className="absolute inset-0 opacity-0 cursor-pointer" />
                <i className="fa-solid fa-upload text-3xl text-[#e10600] mb-2"></i>
                <p className="f1-font text-xs font-bold italic">DRIVER CSV UPLOAD</p>
              </div>
              <div onClick={() => {
                const csv = "grade,class,number,name\n1,A,01,山田 太郎\n1,A,02,佐藤 花子";
                const blob = new Blob([new Uint8Array([0xEF, 0xBB, 0xBF]), csv], { type: 'text/csv' });
                const url = URL.createObjectURL(blob);
                const a = document.createElement('a'); a.href = url; a.download = 'template.csv'; a.click();
              }} className="border-2 border-dashed border-white/10 p-6 rounded text-center hover:bg-white/5 transition-colors cursor-pointer">
                <i className="fa-solid fa-download text-3xl text-white/20 mb-2"></i>
                <p className="f1-font text-xs font-bold italic">TEMPLATE DOWNLOAD</p>
              </div>
            </div>
            {students.length > 0 && (
              <button onClick={() => setLap(2)} className="w-full bg-[#e10600] text-white p-4 f1-font font-black italic rounded skew-x-[-10deg] animate-pulse">GO TO TECH SETUP ({students.length} DRIVERS)</button>
            )}
          </div>
        </div>
      )}

      {lap === 2 && (
        <div className="flex-1 flex flex-col bg-[#1f1f27] rounded overflow-hidden border-b-4 border-[#00ffd2]">
          <div className="p-4 border-b border-white/10 flex justify-between items-center bg-[#15151e]">
            <h2 className="f1-font text-xl font-black italic uppercase"><i className="fa-solid fa-microchip mr-2 text-[#00ffd2]"></i>Tech Setup</h2>
            <div className="flex space-x-4 items-center">
              <button onClick={() => setShowBulkPaste(true)} className="bg-white/10 px-4 py-1 rounded text-[10px] font-black italic hover:bg-white/20 uppercase">Bulk Paste</button>
              <div className="h-6 w-px bg-white/10"></div>
              <label className="text-[10px] font-black text-white/40">Q_COUNT</label>
              <input type="number" value={qCount} onChange={(e) => setQCount(parseInt(e.target.value))} className="bg-black w-12 text-center text-xs f1-font border border-white/10" />
              <button onClick={() => setLap(3)} className="bg-[#00ffd2] text-black px-6 py-1 f1-font font-black italic text-xs skew-x-[-10deg]">CONTINUE</button>
            </div>
          </div>
          <div className="flex-1 overflow-y-auto p-4 bg-black/40">
            <div className="grid grid-cols-1 md:grid-cols-3 lg:grid-cols-5 gap-3">
              {questions.map(q => (
                <div key={q.number} className="bg-[#1f1f27] border border-white/10 rounded overflow-hidden">
