                      </div>
                      <div className="flex-1">
                         <label className="text-[8px] font-black text-white/30 block">POINTS</label>
                         <input type="number" value={q.point} onChange={(e) => updateQ(q.number, 'point', parseInt(e.target.value))} className="w-full bg-black border border-white/10 rounded p-1 text-center font-black f1-font text-white" />
                      </div>
                    </div>
                    <div>
                       <label className="text-[8px] font-black text-white/30 block">SECTION / 大問</label>
                       <input type="text" value={q.section} onChange={(e) => updateQ(q.number, 'section', e.target.value)} className="w-full bg-black border border-white/10 rounded p-1 text-xs font-bold text-center" placeholder="1" />
                    </div>
                    <div>
                       <label className="text-[8px] font-black text-white/30 block">COMPETENCY / 観点</label>
                       <select value={q.competency} onChange={(e) => updateQ(q.number, 'competency', e.target.value)} className="w-full bg-black border border-white/10 rounded p-1 text-[9px] font-bold text-center appearance-none cursor-pointer hover:border-[#00ffd2]">
                         {COMPETENCIES.map(c => <option key={c} value={c}>{c}</option>)}
                       </select>
                    </div>
                  </div>
                </div>
              ))}
            </div>
          </div>
          {showBulkPaste && (
            <div className="fixed inset-0 z-[200] flex items-center justify-center bg-black/90 p-4">
              <div className="bg-[#1f1f27] w-full max-w-lg p-6 rounded border border-white/10">
                <h3 className="f1-font font-black italic mb-4">PASTE ANSWER STRING</h3>
                <textarea value={bulkInput} onChange={(e) => setBulkInput(e.target.value)} className="w-full h-40 bg-black text-[#00ffd2] f1-font p-4 rounded outline-none" placeholder="12345ABCD..." />
                <div className="mt-4 flex justify-end space-x-2">
                  <button onClick={() => setShowBulkPaste(false)} className="px-4 py-2 text-xs font-black">CANCEL</button>
                  <button onClick={() => {
                    const chars = bulkInput.replace(/\s/g,'').split('');
                    setQuestions(prev => prev.map((q, i) => ({ ...q, correctAnswer: chars[i]?.toUpperCase() || q.correctAnswer })));
                    setShowBulkPaste(false);
                  }} className="bg-[#00ffd2] text-black px-6 py-2 f1-font font-black italic text-xs rounded">APPLY</button>
                </div>
              </div>
            </div>
          )}
        </div>
      )}

      {lap === 3 && (
        <div className="max-w-3xl mx-auto w-full bg-[#1f1f27] p-8 rounded border-b-4 border-[#e10600]">
          <h2 className="f1-font text-3xl font-black italic mb-8 uppercase">Lap 3: Data Analysis</h2>
          <div className="grid grid-cols-2 gap-8">
            <div onClick={() => {
              const headers = "student_id," + questions.map(q => `Q${q.number}`).join(',');
              const rows = students.map(s => s.id + "," + questions.map(() => "").join(',')).join('\n');
              const blob = new Blob([new Uint8Array([0xEF, 0xBB, 0xBF]), headers + "\n" + rows], { type: 'text/csv' });
              const a = document.createElement('a'); a.href = URL.createObjectURL(blob); a.download = 'telemetry.csv'; a.click();
            }} className="border-2 border-dashed border-white/10 p-10 rounded text-center hover:bg-white/5 cursor-pointer">
              <i className="fa-solid fa-file-export text-4xl text-[#00ffd2] mb-4"></i>
              <p className="f1-font font-bold">DL TELEMETRY SHEET</p>
            </div>
            <div className="border-2 border-dashed border-white/10 p-10 rounded text-center hover:bg-white/5 cursor-pointer relative">
              <input type="file" accept=".csv" onChange={(e) => {
                const file = e.target.files?.[0]; if (!file) return;
                const reader = new FileReader();
                reader.onload = (ev) => {
                  const lines = (ev.target?.result as string).trim().split('\n');
                  const ans: StudentAnswer[] = lines.slice(1).map(l => {
                    const parts = l.split(',').map(s => s.trim());
                    const answers: Record<number, string> = {};
                    questions.forEach((q, idx) => answers[q.number] = parts[idx+1] || "");
                    return { studentId: parts[0], answers };
                  });
                  onProcess(ans);
                };
                reader.readAsText(file);
              }} className="absolute inset-0 opacity-0 cursor-pointer" />
              <i className="fa-solid fa-microchip text-4xl text-[#e10600] mb-4"></i>
              <p className="f1-font font-bold">UPLOAD FINISHED DATA</p>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

import React from 'react';
import { ScoringResult, Question } from '../types';

export const StatisticsView: React.FC<{ results: ScoringResult[]; questions: Question[] }> = ({ results, questions }) => {
  const avg = results.reduce((a, b) => a + b.score, 0) / results.length;
  const classes = Array.from(new Set(results.map(r => r.student.class)));
  const classStats = classes.map(cls => {
    const clsResults = results.filter(r => r.student.class === cls);
    return { name: cls, avg: clsResults.reduce((a, b) => a + b.score, 0) / clsResults.length, count: clsResults.length };
  });

  const topScorers = [...results].sort((a, b) => b.score - a.score).slice(0, 10);

  return (
    <div className="flex-1 flex flex-col space-y-8 overflow-y-auto pr-4">
      {/* Overview Cards */}
      <div className="grid grid-cols-1 md:grid-cols-4 gap-4">
        <div className="bg-[#1f1f27] p-6 border-l-4 border-[#e10600]">
          <p className="text-[10px] font-black text-white/40 uppercase tracking-widest mb-1">Session Average</p>
          <p className="f1-font text-4xl font-black italic text-white">{avg.toFixed(1)} <span className="text-sm">pts</span></p>
        </div>
        <div className="bg-[#1f1f27] p-6 border-l-4 border-[#00ffd2]">
          <p className="text-[10px] font-black text-white/40 uppercase tracking-widest mb-1">Max Score</p>
          <p className="f1-font text-4xl font-black italic text-[#00ffd2]">{results[0]?.totalPoints} <span className="text-sm text-white">pts</span></p>
        </div>
        <div className="bg-[#1f1f27] p-6 border-l-4 border-white/20">
          <p className="text-[10px] font-black text-white/40 uppercase tracking-widest mb-1">Total Drivers</p>
          <p className="f1-font text-4xl font-black italic text-white">{results.length}</p>
        </div>
        <div className="bg-[#1f1f27] p-6 border-l-4 border-yellow-500">
          <p className="text-[10px] font-black text-white/40 uppercase tracking-widest mb-1">Highest Accuracy</p>
          <p className="f1-font text-4xl font-black italic text-white">{Math.max(...results.map(r => r.accuracy)).toFixed(1)} <span className="text-sm">%</span></p>
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
        {/* Ranking List */}
        <div className="bg-[#1f1f27] rounded overflow-hidden flex flex-col">
          <div className="p-4 bg-[#15151e] border-b border-white/10 flex justify-between items-center">
            <h3 className="f1-font font-black italic text-white/60 uppercase">Driver Standings // TOP 10</h3>
            <span className="text-[10px] font-black text-white/20">REAL-TIME TELEMETRY</span>
          </div>
          <div className="p-2 space-y-1">
            {topScorers.map((r, i) => (
              <div key={r.student.id} className="flex items-center p-3 bg-white/5 border-l-4 border-transparent hover:border-[#e10600] hover:bg-white/10 transition-all group">
                <span className="w-8 f1-font font-black italic text-lg text-white/20 group-hover:text-[#e10600]">P{i+1}</span>
                <span className="w-16 text-[10px] font-black text-white/40">{r.student.class}</span>
                <span className="flex-1 f1-font font-bold text-sm tracking-tight">{r.student.name}</span>
                <span className="f1-font font-black italic text-lg">{r.score.toFixed(0)}</span>
              </div>
            ))}
          </div>
        </div>

        {/* Class Average Analysis */}
        <div className="bg-[#1f1f27] rounded overflow-hidden flex flex-col">
          <div className="p-4 bg-[#15151e] border-b border-white/10 flex justify-between items-center">
            <h3 className="f1-font font-black italic text-white/60 uppercase">Class Average Comparison</h3>
            <span className="text-[10px] font-black text-[#00ffd2]">PERFORMANCE DATA</span>
          </div>
          <div className="p-6 space-y-6">
            {classStats.map(c => (
              <div key={c.name} className="space-y-2">
                <div className="flex justify-between items-end">
                   <span className="f1-font text-xs font-black italic">{c.name}</span>
                   <span className="text-xs font-bold text-white/60">{c.avg.toFixed(1)} pts / {c.count} Drivers</span>
                </div>
                <div className="h-4 bg-black/40 rounded-full overflow-hidden flex">
                  <div 
                    className="h-full bg-gradient-to-r from-[#e10600] to-red-400 transition-all duration-1000" 
                    style={{ width: `${(c.avg / (results[0]?.totalPoints || 1)) * 100}%` }}
                  />
                </div>
              </div>
            ))}
          </div>
        </div>
      </div>
    </div>
  );
};

